INSERT INTO `attractions` VALUES ('A001', '故宫博物院', 'The Palace Museum', '北京', 60.00, 4.9, 28500, 4.9, 'https://travelling123456.oss-cn-beijing.aliyuncs.com/8a2485032be4986c3d96a9506c4b2a92.jpg', '历史古迹', '08:30-17:00', '北京市东城区景山前街4号', 'No.4 Jingshan Front Street, Dongcheng District, Beijing', '中国明清两代的皇家宫殿，世界文化遗产，拥有世界上现存规模最大、保存最为完整的木质结构古建筑之一。', 'The imperial palace of the Ming and Qing dynasties in China, a World Cultural Heritage site, with one of the largest and best-preserved ancient wooden architectural complexes in the world.', '地铁1号线天安门东站', 39.91630000, 116.39720000, '博物馆|世界文化遗产|必打卡', 'Museum|World Cultural Heritage|Must-visit', 15200, '1.2km', '中高', '历史文化');
INSERT INTO `attractions` VALUES ('A002', '颐和园', 'Summer Palace', '北京', 30.00, 4.8, 21000, 4.8, 'https://travelling123456.oss-cn-beijing.aliyuncs.com/0cb7402229298e26dbd29193c1f5b6c1.jpg', '皇家园林', '06:30-18:00', '北京市海淀区新建宫门路19号', 'No.19 Xinjian Gongmen Road, Haidian District, Beijing', '中国清朝时期的皇家园林，是以昆明湖、万寿山为基址，以杭州西湖为蓝本，汲取江南园林的设计手法而建成的一座大型山水园林。', 'A royal garden of the Qing Dynasty in China, built on the basis of Kunming Lake and Wanshou Mountain, modeled after West Lake in Hangzhou, and a large-scale landscape garden designed in the style of Jiangnan gardens.', '地铁4号线北宫门站', 39.99990000, 116.26040000, '皇家园林|自然风光|夏季', 'Royal Garden|Natural Scenery|Summer', 12800, '0.8km', '中', '自然风光');
INSERT INTO `attractions` VALUES ('A003', '西湖', 'West Lake', '杭州', 0.00, 4.7, 35000, 4.7, 'https://travelling123456.oss-cn-beijing.aliyuncs.com/0082f4855772dd90905fe48ba86ed036.jpg', '自然景观', '全天开放', '浙江省杭州市西湖区', 'Xihu District, Hangzhou, Zhejiang Province', '西湖三面环山，湖中被孤山、白堤、苏堤、杨公堤分隔，是中国大陆首批国家重点风景名胜区和中国十大风景名胜之一。', 'Surrounded by mountains on three sides, West Lake is divided by Gushan, Bai Causeway, Su Causeway and Yanggong Causeway. It is one of the first national key scenic spots in mainland China and one of Chinas top ten scenic spots.', '地铁1号线龙翔桥站', 30.26140000, 120.14610000, '自然风光|免费|网红打卡', 'Natural Scenery|Free|Internet-famous', 18900, '0.5km', '低', '自然风光');
INSERT INTO `attractions` VALUES ('A004', '东方明珠广播电视塔', 'Oriental Pearl Tower', '上海', 120.00, 4.6, 28000, 4.6, 'https://travelling123456.oss-cn-beijing.aliyuncs.com/6ca63ff84f986b8405ca737035ea6b67.jpg', '现代地标', '09:00-21:30', '上海市浦东新区陆家嘴环路168号', 'No.168 Lujiazui Ring Road, Pudong New Area, Shanghai', '上海的标志性文化景观之一，是国家5A级旅游景区，塔高约468米，是亚洲第一高塔。', 'One of the iconic cultural landscapes of Shanghai, a national 5A-level tourist attraction, with a tower height of about 468 meters, the tallest tower in Asia.', '地铁2号线陆家嘴站', 31.23580000, 121.49520000, '地标|观光|亲子游', 'Landmark|Sightseeing|Family-friendly', 15600, '0.3km', '高', '现代建筑');
INSERT INTO `attractions` VALUES ('A005', '黄山风景区', 'Huangshan Scenic Area', '黄山', 190.00, 4.9, 15000, 4.9, 'https://travelling123456.oss-cn-beijing.aliyuncs.com/5ce90285ace3b4b67b3185ba4912517a.jpg', '山岳景观', '06:00-17:30', '安徽省黄山市黄山区汤口镇', 'Tangkou Town, Huangshan District, Huangshan City, Anhui Province', '天下第一奇山，世界文化与自然双重遗产，代表景观有“四绝三瀑”，奇松、怪石、云海、温泉享誉中外。', 'The \"No.1 Strange Mountain in the World\", a dual World Heritage Site of culture and nature. Its representative landscapes are \"Four Wonders and Three Waterfalls\", with strange pines, strange rocks, sea of clouds and hot springs famous at home and abroad.', '高铁至黄山北站转大巴', 30.13860000, 118.16870000, '山水|世界遗产|徒步', 'Mountains|World Heritage|Hiking', 9800, '5.0km', '高', '自然风光');
INSERT INTO `attractions` VALUES ('A006', '桂林山水', 'Guilin Scenery', '桂林', 0.00, 4.8, 22000, 4.8, 'https://travelling123456.oss-cn-beijing.aliyuncs.com/66008ee5ad8650d315a8d3008451cb0f.jpg', '山水风光', '全天开放', '广西壮族自治区桂林市', 'Guilin City, Guangxi Zhuang Autonomous Region', '桂林山水甲天下，是世界著名的风景游览城市和中国首批国家历史文化名城，典型的喀斯特地貌。', 'Guilins scenery is the best in the world. It is a world-famous scenic tourist city and one of Chinas first national historical and cultural cities, with typical karst landforms.', '高铁至桂林站', 25.27410000, 110.29930000, '山水|喀斯特|免费', 'Mountains and Rivers|Karst|Free', 16500, '0.6km', '低', '自然风光');
INSERT INTO `attractions` VALUES ('A007', '三亚亚龙湾', 'Yalong Bay,Sanya', '三亚', 0.00, 4.8, 18000, 4.8, 'https://travelling123456.oss-cn-beijing.aliyuncs.com/4a7cb4f8baa60e1399d87f799d4a8e57.jpg', '海滨沙滩', '全天开放', '海南省三亚市亚龙湾国家旅游度假区', 'Yalong Bay National Tourism Resort, Sanya City, Hainan Province', '被誉为“天下第一湾”，拥有7公里长的月牙形海湾，洁白细腻的沙滩和清澈透明的海水。', 'Known as \"the best bay in the world\", it has a 7-kilometer crescent-shaped bay, with white and delicate sand beaches and clear and transparent seawater.', '机场大巴至亚龙湾', 18.20830000, 109.63060000, '海滨|度假|沙滩', 'Coastal|Vacation|Beach', 14200, '2.5km', '中', '自然风光');
INSERT INTO `attractions` VALUES ('A008', '九寨沟', 'Jiuzhaigou Valley', '阿坝', 169.00, 4.9, 12000, 4.9, 'https://travelling123456.oss-cn-beijing.aliyuncs.com/55e3a93de8d427df6caa18ddbfce5363.jpg', '自然保护区', '07:30-17:00', '四川省阿坝藏族羌族自治州九寨沟县', 'Jiuzhaigou County, Aba Tibetan and Qiang Autonomous Prefecture, Sichuan Province', '世界自然遗产，国家重点风景名胜区，以高山湖泊群、瀑布、钙化滩流等水景为主要景观的景区。', 'A World Natural Heritage Site and a national key scenic spot, it is a scenic area with alpine lake groups, waterfalls, calcified beaches and other water landscapes as its main landscapes.', '成都转机或大巴', 33.20300000, 103.82160000, '山水|湖泊|世界遗产', 'Mountains and Lakes|World Heritage', 8500, '15.0km', '高', '自然风光');
INSERT INTO `attractions` VALUES ('A009', '布达拉宫', 'Potala Palace', '拉萨', 200.00, 4.9, 10000, 4.9, 'https://travelling123456.oss-cn-beijing.aliyuncs.com/64c986bebcdeb5e87c3a784c680c7e47.jpg', '宗教建筑', '09:00-15:00', '西藏自治区拉萨市城关区北京中路35号', 'No.35 Beijing Middle Road, Chengguan District, Lhasa City, Xizang Autonomous Region', '世界上海拔最高的宫殿群，世界文化遗产，是藏传佛教格鲁派的重要圣地。', 'The highest palace complex in the world, a World Cultural Heritage Site, and an important sacred site of the Gelug School of Tibetan Buddhism.', '市内公交至布达拉宫站', 29.19490000, 91.11160000, '宗教|历史|高原', 'Religion|History|Plateau', 7200, '0.9km', '高', '历史文化');
INSERT INTO `attractions` VALUES ('A010', '丽江古城', 'Old Town of Lijiang', '丽江', 50.00, 4.8, 20000, 4.8, 'https://travelling123456.oss-cn-beijing.aliyuncs.com/e7fdac4838dab04334d8aaa76f160dd2.jpg', '历史街区', '全天开放', '云南省丽江市古城区', 'Gucheng District, Lijiang City, Yunnan Province', '世界文化遗产，始建于宋末元初，是中国以整座古城申报世界文化遗产获得成功的古城之一。', 'A World Cultural Heritage Site, built at the end of the Song Dynasty and the beginning of the Yuan Dynasty, it is one of the ancient cities in China that successfully applied for World Cultural Heritage as a whole city.', '丽江古城内步行', 26.87030000, 100.23040000, '古城|民族|休闲', 'Ancient City|Ethnic|Leisure', 15800, '0.7km', '中', '历史文化');
INSERT INTO `attractions` VALUES ('A011', '兵马俑', 'Terracotta Army', '西安', 120.00, 4.9, 30000, 4.9, 'https://travelling123456.oss-cn-beijing.aliyuncs.com/851aeabfc9fbdd8d24627999b1287f90.jpg', '考古遗址', '08:30-18:00', '陕西省西安市临潼区秦陵北路', 'Qinling North Road, Lintong District, Xi\'an City, Shaanxi Province', '世界第八大奇迹，世界文化遗产，是世界最大的地下军事博物馆。', 'The Eighth Wonder of the World, a World Cultural Heritage Site, and the largest underground military museum in the world.', '地铁9号线至华清池站', 34.38580000, 109.57000000, '考古|历史|必打卡', 'Archaeology|History|Must-visit', 18500, '8.0km', '高', '历史文化');
INSERT INTO `attractions` VALUES ('A012', '鸣沙山月牙泉', 'Mingsha Mountain and Crescent Spring', '敦煌', 120.00, 4.8, 8000, 4.8, 'https://travelling123456.oss-cn-beijing.aliyuncs.com/560358a4bf606e0be0001e7938c84431.jpg', '沙漠景观', '05:00-21:00', '甘肃省酒泉市敦煌市城南5公里', '5 km south of Dunhuang City, Jiuquan City, Gansu Province', '沙泉共处，妙造天成，古往今来以“沙漠奇观”著称于世。', 'Sand and spring coexist, created by nature, known as \"desert wonder\" since ancient times.', '敦煌市区打车', 40.15330000, 94.68760000, '沙漠|戈壁|日出', 'Desert|Gobi|Sunrise', 5200, '3.0km', '中', '自然风光');
INSERT INTO `attractions` VALUES ('A013', '黄鹤楼', 'Yellow Crane Tower', '武汉', 70.00, 4.7, 15000, 4.7, 'https://travelling123456.oss-cn-beijing.aliyuncs.com/e5f4ae7c32744a6794e5045064606011.jpg', '历史楼阁', '08:30-17:00', '湖北省武汉市武昌区蛇山西坡特1号', 'No.1 West Slope of Sheshan, Wuchang District, Wuhan City, Hubei Province', '“天下绝景”，与岳阳楼、滕王阁并称为“江南三大名楼”，享有“天下江山第一楼”的美誉。', '\"The most beautiful scenery under heaven\", together with Yueyang Tower and Tengwang Pavilion, known as \"Three Great Towers of Jiangnan\", enjoying the reputation of \"the first tower of rivers and mountains in the world\".', '地铁5号线积玉桥站', 30.54240000, 114.32330000, '名楼|历史|江城', 'Famous Tower|History|River City', 11200, '0.4km', '中', '历史文化');
INSERT INTO `attractions` VALUES ('A014', '嵩山少林寺', 'Songshan Shaolin Temple', '郑州', 80.00, 4.8, 18000, 4.8, 'https://travelling123456.oss-cn-beijing.aliyuncs.com/3455ae36825161f0815e0b0717a01efc.jpg', '宗教场所', '08:00-17:00', '河南省郑州市登封市嵩山五乳峰下', 'Under Wuru Peak of Songshan Mountain, Dengfeng City, Zhengzhou City, Henan Province', '中国佛教禅宗祖庭和中国功夫的发源地，是世界文化遗产。', 'The ancestral home of Chinese Zen Buddhism and the birthplace of Chinese Kung Fu, a World Cultural Heritage Site.', '高铁至郑州东站转大巴', 34.50240000, 112.97840000, '武术|宗教|历史', 'Martial Arts|Religion|History', 14800, '12.0km', '中', '历史文化');
INSERT INTO `attractions` VALUES ('A015', '长白山', 'Changbai Mountain', '延边', 120.00, 4.9, 9000, 4.9, 'https://travelling123456.oss-cn-beijing.aliyuncs.com/4b1ee9516667408990299120b37b2ea6.jpg', '火山景观', '07:00-17:00', '吉林省延边朝鲜族自治州安图县', 'Antu County, Yanbian Korean Autonomous Prefecture, Jilin Province', '中国东北的最高峰，是一座休眠火山，天池是其最著名的景观。', 'The highest peak in Northeast China, a dormant volcano, with Tianchi (Heaven Lake) as its most famous landscape.', '飞机至长白山机场', 42.40560000, 128.54750000, '火山|天池|雪景', 'Volcano|Heaven Lake|Snow Scene', 6800, '20.0km', '高', '自然风光');
INSERT INTO `attractions` VALUES ('A016', '太阳岛', 'Sun Island', '哈尔滨', 0.00, 4.6, 10000, 4.6, 'https://travelling123456.oss-cn-beijing.aliyuncs.com/6b6403f35819c622820ef86e2a62ff52.jpg', '城市公园', '全天开放', '黑龙江省哈尔滨市松北区太阳大道1号', 'No.1 Sun Avenue, Songbei District, Harbin City, Heilongjiang Province', '哈尔滨市的城市名片，是由冰雪文化、民俗文化、自然风光构成的游览区。', 'The city card of Harbin, a tourist area composed of ice and snow culture, folk culture and natural scenery.', '地铁2号线太阳岛站', 45.79850000, 126.62320000, '公园|冰雪|休闲', 'Park|Ice and Snow|Leisure', 8200, '1.0km', '低', '自然风光');
INSERT INTO `attractions` VALUES ('A017', '维多利亚港', 'Victoria Harbour', '香港', 0.00, 4.8, 25000, 4.8, 'https://travelling123456.oss-cn-beijing.aliyuncs.com/d5b9d6b43fd4f86612e2f23edc434beb.jpg', '海港景观', '全天开放', '香港特别行政区维多利亚港', 'Victoria Harbour, Hong Kong Special Administrative Region', '亚洲第一大港，是世界三大天然良港之一，每晚的“幻彩咏香江”灯光秀举世闻名。', 'The largest port in Asia, one of the three natural harbors in the world, famous for the \"Symphony of Lights\" show every night.', '港铁至尖沙咀站', 22.28550000, 114.16830000, '海港|夜景|城市', 'Harbour|Night View|City', 19500, '0.2km', '低', '自然风光');
INSERT INTO `attractions` VALUES ('A018', '大三巴牌坊', 'Ruins of St. Paul\'s', '澳门', 10.00, 4.7, 12000, 4.7, 'https://travelling123456.oss-cn-beijing.aliyuncs.com/b6fe51266442258be27901ae552dfd2e.jpg', '历史建筑', '09:00-18:00', '澳门特别行政区大堂区大三巴街', 'San Ba Street, Da Tang District, Macao Special Administrative Region', '澳门的标志性建筑物之一，原为圣保禄大教堂的前壁，是“澳门历史城区”的重要组成部分。', 'One of the iconic buildings of Macau, originally the front wall of St. Paul\'s Cathedral, an important part of the \"Historic Centre of Macao\".', '澳门半岛步行', 22.19580000, 113.54870000, '历史|宗教|地标', 'History|Religion|Landmark', 9800, '0.3km', '低', '历史文化');
INSERT INTO `attractions` VALUES ('A019', '张家界国家森林公园', 'Zhangjiajie National Forest Park', '张家界', 225.00, 4.9, 20000, 4.9, 'https://travelling123456.oss-cn-beijing.aliyuncs.com/4a42afa6b536712600f2928431047698.jpg', '石英砂岩峰林', '07:30-18:00', '湖南省张家界市武陵源区', 'Wulingyuan District, Zhangjiajie City, Hunan Province', '世界自然遗产，以峰林、溶洞、峡谷、溪流、森林等自然风光为主，被誉为“中国山水画的原本”。', 'A World Natural Heritage Site, dominated by natural scenery such as peak forests, karst caves, canyons, streams and forests, known as \"the original of Chinese landscape painting\".', '高铁至张家界西站', 29.13190000, 110.48310000, '峰林|世界遗产|徒步', 'Peak Forest|World Heritage|Hiking', 16200, '10.0km', '高', '自然风光');
INSERT INTO `attractions` VALUES ('A020', '鼓浪屿', 'Gulangyu Island', '厦门', 0.00, 4.8, 16000, 4.8, 'https://travelling123456.oss-cn-beijing.aliyuncs.com/249d5409066644cab98c2fcff3327e77.jpg', '历史岛屿', '全天开放', '福建省厦门市思明区鼓浪屿', 'Gulangyu Island, Siming District, Xiamen City, Fujian Province', '世界文化遗产，岛上气候宜人，四季如春，无车马喧嚣，有“海上花园”之美誉。', 'A World Cultural Heritage Site, with pleasant climate, four seasons like spring, no noise of cars and horses, known as \"sea garden\".', '邮轮中心厦鼓码头', 24.43570000, 118.08740000, '岛屿|历史|文艺', 'Island|History|Artistic', 13500, '5.0km', '中', '历史文化');
INSERT INTO `attractions` VALUES ('S004', '归元禅寺', 'Guiyuan Temple', '武汉', 20.00, 4.5, 12345, 4.5, 'https://travelling123456.oss-cn-beijing.aliyuncs.com/b573ecc9d97dbd3d54d6c2ee9b90649e.jpg', '宗教寺庙', '08:00-17:00', '汉阳区翠微路20号', 'No.20 Cuiwei Road, Hanyang District', '武汉四大丛林之一，以建筑精美、佛像众多、香火旺盛而闻名，是祈福游览的胜地。', 'One of the four major jungles in Wuhan, famous for exquisite architecture, numerous Buddha statues and prosperous incense, a holy place for praying and sightseeing.', '地铁4号线到钟家村站，步行约1公里；或公交26、42、531、535路到归元寺站', 30.56060000, 114.25340000, '祈福,古刹,宁静,佛教', 'Prayer|Ancient Temple|Peace|Buddhism', 12345, '6.7km', 'Paid', '佛教寺院');
INSERT INTO `attractions` VALUES ('S005', '汉口江滩', 'Hankou River Beach', '武汉', 0.00, 4.4, 23456, 4.4, 'https://travelling123456.oss-cn-beijing.aliyuncs.com/543fb6b9544fd2c685c6cf4af2239a28.jpg', '城市公园', '全天开放', '江岸区沿江大道', 'Yanjiang Avenue, Jiang\'an District', '长江边的大型江滩公园，是武汉人散步、看江景、赏夜景的绝佳去处。', 'A large river beach park by the Yangtze River, an excellent place for Wuhan people to walk, enjoy river views and night views.', '地铁2号线到江汉路站，步行约1公里；或公交1、7、30、212路到沿江大道兰陵路站', 30.57880000, 114.28910000, '江景,散步,夜景,城市公园', 'River View|Walk|Night View|City Park', 23456, '7.1km', 'Free', '江滩公园');
