INSERT INTO `intangible` VALUES ('I001', '汉绣', '武汉', '省级', '色彩艳丽、针法细腻', '始于汉代，盛于明清', '体验汉绣针法，制作小荷包', '武汉汉绣博物馆', '传统技艺', '华中', '汉绣是武汉地区的传统刺绣工艺，以楚文化为底蕴，色彩浓郁，针法丰富。', 'https://travelling123456.oss-cn-beijing.aliyuncs.com/6fa660dd04e248fa30d51ad4c5567f3d.jpg', '非遗,传统文化,刺绣', 120, 45, 3200, '武汉市汉阳区古琴台', '027-84812345', 98, '2024-01-15 10:00:00');
INSERT INTO `intangible` VALUES ('I002', '热干面制作技艺', '武汉', '市级', '面条筋道、麻酱香浓', '源于清末民初，武汉过早代表', '体验和面、掸面、调酱', '蔡林记', '传统技艺', '华中', '热干面是武汉最具代表性的过早小吃，制作工艺讲究，口感筋道，麻酱香浓。', 'https://travelling123456.oss-cn-beijing.aliyuncs.com/539d46236b7f592c5e0ae51d5e08f188.jpg', '非遗,美食,过早', 250, 89, 5600, '武汉市武昌区户部巷', '027-88866666', 38, '2024-01-16 11:00:00');
INSERT INTO `intangible` VALUES ('I003', '京剧', '北京', '国家级', '唱念做打、虚实结合', '形成于清代乾隆末年', '体验京剧身段、唱腔', '国家京剧院', '表演艺术', '华北', '京剧是中国国粹，融合唱、念、做、打，被誉为“东方歌剧”。', 'https://travelling123456.oss-cn-beijing.aliyuncs.com/ae39cc10e61e3ca4d9dd042fffb5877a.jpg', '非遗,国粹,戏曲', 320, 120, 7800, '北京市西城区平安里', '010-66182345', 198, '2024-01-17 09:30:00');
INSERT INTO `intangible` VALUES ('I004', '北京烤鸭制作技艺', '北京', '国家级', '皮脆肉嫩、肥而不腻', '源于明代，宫廷美食走向民间', '体验片鸭、卷饼', '全聚德', '传统技艺', '华北', '北京烤鸭是北京美食代表，以果木炭火烤制，皮脆肉嫩，肥而不腻。', 'https://travelling123456.oss-cn-beijing.aliyuncs.com/2d1b1bcf786d5b932d363fe5498f6730.jpg', '非遗,美食,宫廷', 450, 180, 9200, '北京市东城区前门大街', '010-65112345', 298, '2024-01-18 14:00:00');
INSERT INTO `intangible` VALUES ('I005', '越剧', '杭州', '国家级', '唱腔婉转、唯美典雅', '发源于浙江嵊州，流行于江南', '体验越剧水袖、唱腔', '浙江小百花越剧团', '表演艺术', '华东', '越剧是中国第二大剧种，以抒情、细腻、优美著称，擅长表现才子佳人故事。', 'https://travelling123456.oss-cn-beijing.aliyuncs.com/73f849db390cb03ffab42fa386324087.jpg', '非遗,戏曲,江南', 210, 75, 4500, '杭州市西湖区文化广场', '0571-88001234', 168, '2024-01-19 15:30:00');
INSERT INTO `intangible` VALUES ('I006', '西湖龙井制作技艺', '杭州', '国家级', '色绿、香郁、味甘、形美', '源于唐，盛于清，位列中国十大名茶', '体验采茶、炒茶', '西湖龙井村', '传统技艺', '华东', '西湖龙井是中国十大名茶之首，产于杭州西湖周边，制作工艺精湛，品质优异。', 'https://travelling123456.oss-cn-beijing.aliyuncs.com/a8b15dab92bef6b91715afc115c8d61c.jpg', '非遗,茶叶,茶文化', 380, 135, 6800, '杭州市西湖区龙井村', '0571-87961234', 268, '2024-01-20 10:15:00');
INSERT INTO `intangible` VALUES ('I007', '粤剧', '广州', '国家级', '唱腔优美、行当齐全', '形成于清代中叶，岭南文化代表', '体验粤剧锣鼓、唱腔', '广州粤剧院', '表演艺术', '华南', '粤剧是岭南文化的瑰宝，融合唱、做、念、打，具有浓郁的岭南特色。', 'https://travelling123456.oss-cn-beijing.aliyuncs.com/6c7fc4a6b03a578ce60bdeaebaedebab.jpg', '非遗,戏曲,岭南', 190, 68, 4200, '广州市天河区珠江新城', '020-38392345', 188, '2024-01-21 16:45:00');
INSERT INTO `intangible` VALUES ('I008', '广彩瓷烧制技艺', '广州', '国家级', '色彩艳丽、构图饱满', '源于清代康熙年间，外销瓷代表', '体验彩绘、烧制', '广彩大师工作室', '传统技艺', '华南', '广彩瓷是广州传统工艺美术品，以色彩艳丽、构图饱满、金碧辉煌著称。', 'https://travelling123456.oss-cn-beijing.aliyuncs.com/8dfe74a0239b099384ba6c3519fbd356.jpg', '非遗,陶瓷,外销', 270, 95, 5300, '广州市荔湾区陈家祠', '020-81812345', 328, '2024-01-22 09:00:00');
INSERT INTO `intangible` VALUES ('I009', '川剧变脸', '成都', '国家级', '瞬间变脸、神秘莫测', '源于清代，川剧绝活', '体验变脸手法、表演', '成都川剧院', '表演艺术', '西南', '川剧变脸是川剧表演的绝活，通过瞬间变换脸谱，表现人物情绪变化，极具观赏性。', 'https://travelling123456.oss-cn-beijing.aliyuncs.com/1be5d24dc3000bb96aa2930803abbf89.jpg', '非遗,戏曲,绝活', 420, 150, 8500, '成都市锦江区华兴街', '028-86622345', 158, '2024-01-23 11:30:00');
INSERT INTO `intangible` VALUES ('I010', '蜀绣', '成都', '国家级', '针法细腻、色彩丰富', '始于汉代，与苏绣、湘绣、粤绣并称四大名绣', '体验蜀绣针法、绣制', '蜀绣大师工作室', '传统技艺', '西南', '蜀绣是中国四大名绣之一，以针法细腻、色彩丰富、题材广泛著称。', 'https://travelling123456.oss-cn-beijing.aliyuncs.com/e447cfb61df38398e9ea62991f4beadd.jpg', '非遗,刺绣,四大名绣', 310, 110, 6200, '成都市青羊区宽窄巷子', '028-86261234', 298, '2024-01-24 14:45:00');
INSERT INTO `intangible` VALUES ('I011', '秦腔', '西安', '国家级', '唱腔高亢、慷慨激昂', '源于古代陕甘地区，梆子腔代表', '体验秦腔唱腔、板胡', '西安易俗社', '表演艺术', '西北', '秦腔是中国最古老的戏曲剧种之一，以唱腔高亢、慷慨激昂、富有西北风情著称。', 'https://travelling123456.oss-cn-beijing.aliyuncs.com/e26b39274fb63a3c328366e802a3a156.jpg', '非遗,戏曲,西北', 180, 62, 3900, '西安市新城区案板街', '029-87212345', 128, '2024-01-25 10:30:00');
INSERT INTO `intangible` VALUES ('I012', '西安肉夹馍制作技艺', '西安', '省级', '馍香肉酥、肥而不腻', '源于战国时期，“中式汉堡”', '体验打馍、卤肉', '子午路张记', '传统技艺', '西北', '肉夹馍是西安传统美食，馍香肉酥，肥而不腻，被誉为“中式汉堡”。', 'https://travelling123456.oss-cn-beijing.aliyuncs.com/7f93807cdcda7d683c6591792bad9690.jpg', '非遗,美食,中式汉堡', 350, 125, 7200, '西安市雁塔区子午路', '029-85212345', 28, '2024-01-26 13:15:00');
INSERT INTO `intangible` VALUES ('I013', '剪纸', '延安', '国家级', '线条流畅、造型生动', '源于古代祭祀，流行于民间', '体验剪纸技法、创作', '安塞剪纸村', '传统技艺', '西北', '剪纸是中国民间传统艺术，通过剪刀或刻刀在纸上剪刻出各种图案，造型生动，寓意吉祥。', 'https://travelling123456.oss-cn-beijing.aliyuncs.com/54f70948e35aa02f674d4767f57c11e5.jpg', '非遗,民间艺术,剪纸', 240, 85, 5100, '延安市安塞区', '0911-6212345', 68, '2024-01-27 15:00:00');
INSERT INTO `intangible` VALUES ('I014', '安塞腰鼓', '延安', '国家级', '气势磅礴、刚劲奔放', '源于古代战争，陕北民间舞蹈', '体验腰鼓表演、节奏', '安塞腰鼓队', '表演艺术', '西北', '安塞腰鼓是陕北民间舞蹈，以气势磅礴、刚劲奔放、节奏强烈著称，被誉为“天下第一鼓”。', 'https://travelling123456.oss-cn-beijing.aliyuncs.com/6336558c6a495e320764b4a3031ea233.jpg', '非遗,舞蹈,陕北', 390, 140, 8100, '延安市安塞区', '0911-6312345', 98, '2024-01-28 09:45:00');
