INSERT INTO `travel_plan` VALUES ('TP00dfe62d15', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第一天（北京）：抵达北京，游览故宫、天安门广场\', \'spots\': [\'故宫\', \'天安门广场\']}, {\'day\': 2, \'content\': \'第二天（北京）：参观颐和园、圆明园\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第三天（北京）：游览长城、返回\', \'spots\': [\'八达岭长城\']}]', '北京推荐：北京如家酒店', '北京美食：烤鸭、炸酱面、豆汁儿', '1. 北京地铁便捷，建议购买交通卡；2. 长城需早起，注意保暖', '2026-03-17 21:00:55', '[\'文化深度体验\', \'景点集中方便游览\', \'预算合理\', \'适合历史文化爱好者\']');
INSERT INTO `travel_plan` VALUES ('TP03c659857b', 1, '北京', 8, 3000, 'culturalExploration', '我想去北京，然后再到长沙，最后返回北京', '[{\'day\': 1, \'content\': \'第一天抵达北京，游览天安门广场和故宫\', \'spots\': [\'天安门广场\', \'故宫\']}, {\'day\': 2, \'content\': \'第二天参观颐和园和圆明园\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第三天前往八达岭长城，感受历史气息\', \'spots\': [\'八达岭长城\']}, {\'day\': 4, \'content\': \'第四天前往长沙，开始探索湖南文化\', \'spots\': []}, {\'day\': 5, \'content\': \'第五天游览岳麓山和橘子洲头\', \'spots\': [\'岳麓山\', \'橘子洲头\']}, {\'day\': 6, \'content\': \'第六天参观湖南省博物馆，了解湖湘文化\', \'spots\': [\'湖南省博物馆\']}, {\'day\': 7, \'content\': \'第七天自由活动，体验长沙美食和市井文化\', \'spots\': []}, {\'day\': 8, \'content\': \'第八天返回北京，结束旅程\', \'spots\': []}]', '推荐选择市中心地段的经济型酒店，方便出行和购物。', '北京可尝试烤鸭、炸酱面；长沙必尝口味虾、臭豆腐和辣椒炒肉。', '提前预订交通票，注意天气变化，携带身份证件，尊重当地文化和习俗。', '2026-03-12 20:30:38', NULL);
INSERT INTO `travel_plan` VALUES ('TP118a3225ff', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第一天（北京）：游览故宫、天安门广场\', \'spots\': [\'故宫\', \'天安门广场\']}, {\'day\': 2, \'content\': \'第二天（北京）：参观长城、颐和园\', \'spots\': [\'长城\', \'颐和园\']}, {\'day\': 3, \'content\': \'第三天（北京）：探索798艺术区、奥林匹克公园\', \'spots\': [\'798艺术区\', \'奥林匹克公园\']}]', '北京推荐：北京丽枫酒店', '北京美食：烤鸭、炸酱面、豆汁焦圈', '1. 北京地铁覆盖广泛，建议使用交通卡；2. 长城建议穿舒适的鞋子；3. 烤鸭需提前预订', '2026-03-17 20:43:28', NULL);
INSERT INTO `travel_plan` VALUES ('TP128439afb7', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第一天（北京）：抵达北京，游览故宫、天坛\', \'spots\': [\'故宫\', \'天坛\']}, {\'day\': 2, \'content\': \'第二天（北京）：参观长城、颐和园\', \'spots\': [\'长城\', \'颐和园\']}, {\'day\': 3, \'content\': \'第三天（北京）：逛南锣鼓巷、体验胡同文化\', \'spots\': [\'南锣鼓巷\', \'胡同\']}]', '北京推荐：北京如家酒店', '北京美食：烤鸭、豆汁焦圈', '1. 北京地铁方便，建议购买交通卡；2. 冬季注意保暖', '2026-03-17 20:42:46', NULL);
INSERT INTO `travel_plan` VALUES ('TP16ee05d1e1', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京，然后去长沙', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'故宫\', \'天坛公园\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'国家博物馆\', \'南锣鼓巷\']}]', '推荐住在市中心，方便前往各个景点，如王府井附近酒店。', '尝试北京烤鸭、炸酱面、豆汁儿等特色美食。', '提前预订景点门票，避免排队；注意保暖，北京早晚温差大。', '2026-03-12 20:36:44', NULL);
INSERT INTO `travel_plan` VALUES ('TP1841b97fbc', 1, '北京', 7, 3000, 'culturalExploration', '我要去北京', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'故宫\', \'天安门广场\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'八达岭长城\']}, {\'day\': 4, \'content\': \'第四天行程描述\', \'spots\': [\'国家博物馆\', \'南锣鼓巷\']}, {\'day\': 5, \'content\': \'第五天行程描述\', \'spots\': [\'景山公园\', \'雍和宫\']}, {\'day\': 6, \'content\': \'第六天行程描述\', \'spots\': [\'北海公园\', \'后海\']}, {\'day\': 7, \'content\': \'第七天行程描述\', \'spots\': [\'首都博物馆\']}]', '推荐住在市中心，方便出行，如王府井或西单附近。', '尝试老北京炸酱面、烤鸭、豆汁焦圈等特色美食。', '提前预订景点门票，注意天气变化，携带身份证件。', '2026-03-04 17:30:51', NULL);
