INSERT INTO `travel_plan` VALUES ('TP1f59255a57', 1, '武汉', 6, 3000, 'culturalExploration', '我想从北京再到长沙', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'黄鹤楼\', \'长江大桥\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'东湖风景区\', \'湖北省博物馆\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'古琴台\', \'晴川阁\']}, {\'day\': 4, \'content\': \'第四天行程描述\', \'spots\': [\'归元寺\', \'汉口江滩\']}, {\'day\': 5, \'content\': \'第五天行程描述\', \'spots\': [\'武汉大学\', \'东湖落雁景区\']}, {\'day\': 6, \'content\': \'第六天行程描述\', \'spots\': [\'楚河汉街\', \'长江轮渡\']}]', '推荐入住武昌区的酒店，方便游览市区景点。', '必尝热干面、豆皮、鸭脖和武昌鱼。', '武汉夏季较热，注意防晒；地铁覆盖广泛，建议使用地铁出行。', '2026-03-12 20:37:44', NULL);
INSERT INTO `travel_plan` VALUES ('TP208fc0b4e2', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第一天（北京）：抵达北京，游览故宫、天坛\', \'spots\': [\'故宫\', \'天坛\']}, {\'day\': 2, \'content\': \'第二天（北京）：参观长城、颐和园\', \'spots\': [\'八达岭长城\', \'颐和园\']}, {\'day\': 3, \'content\': \'第三天（北京）：游览798艺术区、购买纪念品\', \'spots\': [\'798艺术区\']}]', '北京推荐：北京7天酒店', '北京美食：烤鸭、豆汁焦圈、炸酱面', '1. 北京地铁覆盖广，建议使用交通卡；2. 长城游玩需注意体力，穿舒适鞋子', '2026-03-17 21:01:09', '[\'文化体验丰富\', \'景点集中省时\', \'交通方便快捷\', \'适合深度探索\']');
INSERT INTO `travel_plan` VALUES ('TP20f8cb7cae', 1, '武汉', 3, 3000, 'culturalExploration', 'I want to visit Wuhan for 3 days, mainly want to see Yellow Crane Tower and East Lake, enjoy local snacks, hope to stay in a comfortable hotel near the subway, budget about 3000 yuan.', '[{\'day\': 1, \'content\': \'第一天（武汉）：抵达武汉，游览黄鹤楼、长江大桥\', \'spots\': [\'黄鹤楼\', \'长江大桥\']}, {\'day\': 2, \'content\': \'第二天（武汉）：参观东湖风景区、湖北省博物馆\', \'spots\': [\'东湖风景区\', \'湖北省博物馆\']}, {\'day\': 3, \'content\': \'第三天（武汉）：品尝武汉小吃，游览户部巷\', \'spots\': [\'户部巷\', \'热干面\']}]', '武汉推荐：武汉全季酒店（靠近地铁）', '武汉美食：热干面、豆皮、鸭脖', '1. 武汉景点之间交通便利，建议使用地铁；2. 热干面是必尝小吃；3. 黄鹤楼和东湖可安排在同一天游览', '2026-03-12 21:05:35', NULL);
INSERT INTO `travel_plan` VALUES ('TP2357aea475', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第一天（北京）：抵达北京，游览故宫、天坛\', \'spots\': [\'故宫\', \'天坛\']}, {\'day\': 2, \'content\': \'第二天（北京）：参观颐和园、圆明园\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第三天（北京）：游览长城、品尝北京烤鸭\', \'spots\': [\'长城\', \'北京烤鸭\']}]', '北京推荐：北京京仪大酒店', '北京美食：炸酱面、豆汁焦圈、北京烤鸭', '1. 北京地铁方便，建议购买交通卡；2. 长城需提前预约门票；3. 注意保暖，北京早晚温差大', '2026-03-17 20:27:15', NULL);
INSERT INTO `travel_plan` VALUES ('TP29b3adcd27', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第1天（北京）：早上7:30酒店出发，乘坐地铁2号线至天安门广场，游玩2小时；随后步行至故宫，参观3小时；中午在故宫附近用餐；下午参观景山公园，傍晚返回酒店休息。\', \'spots\': [\'天安门广场\', \'故宫\', \'景山公园\']}, {\'day\': 2, \'content\': \'第2天（北京）：早上8:00酒店出发，打车前往八达岭长城，游览3小时；中午在长城附近用餐；下午参观居庸关长城，傍晚返回市区。\', \'spots\': [\'八达岭长城\', \'居庸关长城\']}, {\'day\': 3, \'content\': \'第3天（北京）：早上9:00酒店出发，乘坐地铁至颐和园，游玩2.5小时；中午在颐和园附近用餐；下午参观圆明园，傍晚返回酒店并准备返程。\', \'spots\': [\'颐和园\', \'圆明园\']}]', '北京推荐：天安门或故宫附近酒店', '北京美食：烤鸭、炸酱面、豆汁焦圈', '1. 北京景点多，建议使用地铁或打车；2. 高峰期人多，尽量早起游览；3. 注意保暖，北京早晚温差大', '2026-03-19 22:31:22', '[\'深度文化体验\', \'经典景点全覆盖\', \'交通便捷高效\', \'行程合理不赶路\']');
INSERT INTO `travel_plan` VALUES ('TP2ebdea8dc9', 1, '北京/上海', 6, 3000, 'culturalExploration', '我想去北京，然后去上海', '[{\'day\': 1, \'content\': \'第1天（北京）：抵达北京，游览故宫、天坛\', \'spots\': [\'故宫\', \'天坛\']}, {\'day\': 2, \'content\': \'第2天（北京）：参观颐和园、圆明园\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第3天（北京）：游览长城（八达岭）、品尝北京烤鸭\', \'spots\': [\'八达岭长城\', \'北京烤鸭\']}, {\'day\': 4, \'content\': \'第4天（北京）：从北京前往上海，参观外滩、南京路步行街\', \'spots\': [\'外滩\', \'南京路步行街\']}, {\'day\': 5, \'content\': \'第5天（上海）：游览豫园、城隍庙\', \'spots\': [\'豫园\', \'城隍庙\']}, {\'day\': 6, \'content\': \'第6天（上海）：参观上海博物馆、陆家嘴观光区\', \'spots\': [\'上海博物馆\', \'陆家嘴观光区\']}]', '北京推荐：XX酒店；上海推荐：XX酒店', '北京美食：烤鸭、炸酱面；上海美食：小笼包、生煎包', '1. 北京到上海高铁约5小时；2. 上海景点密集，建议使用地铁或打车', '2026-03-12 20:50:56', NULL);
INSERT INTO `travel_plan` VALUES ('TP35006a32a3', 1, '上海', 3, 3000, 'culturalExploration', '我想去上海', '[{\'day\': 1, \'content\': \'第1天（上海）：早上8:00从酒店出发，步行15分钟至外滩，游玩1小时；中午在南京东路附近用餐；下午乘坐地铁2号线至豫园，游览2小时；晚上返回外滩欣赏夜景。\', \'spots\': [\'外滩\', \'豫园\']}, {\'day\': 2, \'content\': \'第2天（上海）：早上9:00乘坐地铁10号线至上海博物馆，参观2小时；中午在人民广场附近用餐；下午步行至上海图书馆，参观1小时；傍晚前往静安寺购物和用餐。\', \'spots\': [\'上海博物馆\', \'上海图书馆\', \'静安寺\']}, {\'day\': 3, \'content\': \'第3天（上海）：早上8:30乘坐地铁4号线至田子坊，游览1.5小时；中午在附近用餐；下午前往新天地，参观1小时；傍晚返回酒店，结束行程。\', \'spots\': [\'田子坊\', \'新天地\']}]', '上海推荐：外滩或南京东路附近酒店', '上海美食：小笼包、生煎、蟹粉汤包', '1. 上海地铁发达，建议使用交通卡；2. 注意夏季高温，携带防晒用品；3. 部分景点需提前预约', '2026-03-19 21:58:28', '[\'深度文化体验\', \'景点集中便于游览\', \'美食丰富多样\', \'交通便捷\']');
INSERT INTO `travel_plan` VALUES ('TP37d935649e', 1, '上海', 3, 3000, 'culturalExploration', '我想去上海', '[{\'day\': 1, \'content\': \'第一天（上海）：抵达上海，游览外滩、南京路步行街\', \'spots\': [\'外滩\', \'南京路步行街\']}, {\'day\': 2, \'content\': \'第二天（上海）：参观上海博物馆、豫园\', \'spots\': [\'上海博物馆\', \'豫园\']}, {\'day\': 3, \'content\': \'第三天（上海）：游览田子坊、东方明珠塔\', \'spots\': [\'田子坊\', \'东方明珠塔\']}]', '上海推荐：上海浦东香格里拉大酒店', '上海美食：小笼包、生煎、蟹粉汤包', '1. 上海地铁方便，建议购买交通卡；2. 旅游景点人多，注意保管好随身物品', '2026-03-17 20:19:55', NULL);
INSERT INTO `travel_plan` VALUES ('TP396a6299cc', 1, '武汉', 3, 3000, 'culturalExploration', '我想去武汉玩3天，主要想看黄鹤楼和东湖，喜欢吃当地小吃，希望住在地铁附近的舒适型酒店，预算大约3000元。', '[{\'day\': 1, \'content\': \'抵达武汉，前往黄鹤楼景区游览，了解其历史文化。随后在附近品尝热干面、豆皮等当地小吃。\', \'spot\': [\'黄鹤楼\']}, {\'day\': 2, \'content\': \'全天游览东湖绿道，骑行或步行欣赏湖光山色，参观听涛景区和磨山景区。晚上在东湖周边尝试地道的武汉菜。\', \'spot\': [\'东湖绿道\', \'听涛景区\', \'磨山景区\']}, {\'day\': 3, \'content\': \'参观湖北省博物馆（可选），了解楚文化。随后前往武昌古城，体验老街风情，并购买纪念品。返程。\', \'spot\': [\'湖北省博物馆\', \'武昌古城\']}]', '武汉地铁2号线沿线舒适型酒店，如汉口火车站附近酒店，预算约600元/晚。', '推荐品尝热干面、豆皮、鸭脖、武昌鱼、汤包等武汉特色小吃和菜肴。', '建议提前预订景点门票，避免排队；地铁出行方便，可携带交通卡或使用手机支付；注意饮食卫生，适量尝试辣味菜品。', '2026-03-04 08:49:06', NULL);
INSERT INTO `travel_plan` VALUES ('TP397db73d7c', 1, '武汉', 3, 3000, 'culturalExploration', 'I want to visit Wuhan for 3 days, mainly want to see Yellow Crane Tower and East Lake, enjoy local snacks, hope to stay in a comfortable hotel near the subway, budget about 3000 yuan.', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'黄鹤楼\', \'户部巷\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'东湖风景区\', \'湖北省博物馆\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'长江大桥\', \'昙华林\']}]', '推荐入住地铁附近舒适酒店，方便出行。', '推荐尝试热干面、豆皮、武昌鱼等当地特色小吃。', '建议提前预订景点门票，避免排队；注意防晒和携带身份证件。', '2026-03-12 20:46:09', NULL);
INSERT INTO `travel_plan` VALUES ('TP3d6859d6ac', 1, '上海', 3, 3000, 'culturalExploration', '我想去上海', '[{\'day\': 1, \'content\': \'第一天（上海）：抵达上海，游览外滩、南京路步行街\', \'spots\': [\'外滩\', \'南京路步行街\']}, {\'day\': 2, \'content\': \'第二天（上海）：参观上海博物馆、豫园\', \'spots\': [\'上海博物馆\', \'豫园\']}, {\'day\': 3, \'content\': \'第三天（上海）：游览田子坊、新天地\', \'spots\': [\'田子坊\', \'新天地\']}]', '上海推荐：上海浦东丽思卡尔顿酒店', '上海美食：小笼包、生煎、蟹粉汤包', '1. 上海地铁便捷，建议购买交通卡；2. 夏季注意防晒', '2026-03-17 20:25:19', NULL);
INSERT INTO `travel_plan` VALUES ('TP3e4aab0efe', 1, '安徽潜山', 10, 3000, 'culturalExploration', '我想从黑龙江去安徽潜山，沿途经过上海和武汉', '[{\'day\': 1, \'content\': \'从黑龙江出发，前往上海，游览外滩和豫园\', \'spots\': [\'外滩\', \'豫园\']}, {\'day\': 2, \'content\': \'在上海继续游玩，参观上海博物馆和南京路步行街\', \'spots\': [\'上海博物馆\', \'南京路步行街\']}, {\'day\': 3, \'content\': \'乘坐高铁前往武汉，游览黄鹤楼和东湖绿道\', \'spots\': [\'黄鹤楼\', \'东湖绿道\']}, {\'day\': 4, \'content\': \'在武汉参观湖北省博物馆，了解楚文化\', \'spots\': [\'湖北省博物馆\']}, {\'day\': 5, \'content\': \'前往安徽潜山，抵达后参观天柱山景区\', \'spots\': [\'天柱山\']}, {\'day\': 6, \'content\': \'游览潜山市内的古迹，如潜山文庙和薛家岗遗址\', \'spots\': [\'潜山文庙\', \'薛家岗遗址\']}, {\'day\': 7, \'content\': \'探索潜山的自然风光，如槎水风景区\', \'spots\': [\'槎水风景区\']}, {\'day\': 8, \'content\': \'前往安庆市，参观迎江寺和振风塔\', \'spots\': [\'迎江寺\', \'振风塔\']}, {\'day\': 9, \'content\': \'返回潜山，自由活动，购买当地特产\', \'spots\': [\'当地特产店\']}, {\'day\': 10, \'content\': \'结束行程，返回黑龙江\', \'spots\': []}]', '推荐选择交通便利、价格适中的酒店，如上海和武汉的连锁酒店，潜山可选择靠近景点的客栈或经济型酒店。', '尝试上海的小笼包、武汉的热干面、潜山的潜山豆腐和当地特色小吃。', '提前规划好交通路线，预留足够时间休息；注意天气变化，携带适合的衣物；合理安排预算，避免超支。', '2026-03-04 09:04:46', NULL);
INSERT INTO `travel_plan` VALUES ('TP40ee0d23fd', 1, '北京', 5, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第一天（北京）：抵达北京，游览天安门广场、故宫\', \'spots\': [\'天安门广场\', \'故宫\']}, {\'day\': 2, \'content\': \'第二天（北京）：参观颐和园、圆明园\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第三天（北京）：游览八达岭长城、居庸关\', \'spots\': [\'八达岭长城\', \'居庸关\']}, {\'day\': 4, \'content\': \'第四天（北京）：参观国家博物馆、天坛公园\', \'spots\': [\'国家博物馆\', \'天坛公园\']}, {\'day\': 5, \'content\': \'第五天（北京）：自由活动，购买纪念品，返程\', \'spots\': []}]', '北京推荐：北京京西宾馆；如需经济型可选北京青年旅舍', '北京美食：烤鸭、炸酱面、豆汁焦圈、糖葫芦', '1. 北京地铁覆盖广，建议使用交通卡或手机支付；2. 冬季寒冷，注意保暖；3. 故宫等景点需提前预约', '2026-03-12 21:08:33', NULL);
INSERT INTO `travel_plan` VALUES ('TP4253fcf6b9', 1, '武汉', 3, 3000, 'culturalExploration', '我想去武汉玩3天，主要想看黄鹤楼和东湖，喜欢吃当地小吃，希望住在地铁附近的舒适型酒店，预算大约3000元。', '[{\'day\': 1, \'content\': \'抵达武汉，前往黄鹤楼景区参观，了解其历史文化背景。\', \'spot\': [\'黄鹤楼\']}, {\'day\': 2, \'content\': \'游览东湖风景区，欣赏湖光山色，体验自然与人文景观的结合。\', \'spot\': [\'东湖\']}, {\'day\': 3, \'content\': \'参观湖北省博物馆，探索楚文化，品尝武汉特色小吃如热干面、豆皮等。\', \'spot\': [\'湖北省博物馆\']}]', '武汉地铁口舒适型酒店（如武昌站附近），方便出行且性价比高。', '推荐尝试热干面、豆皮、鸭脖、汤包、藕粉等武汉特色小吃。', '建议提前预订景点门票，使用地铁出行更便捷，注意天气变化并准备适合的衣物。', '2026-03-04 08:43:09', NULL);
INSERT INTO `travel_plan` VALUES ('TP45f8cfd548', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第1天（北京）：早上7:30从酒店出发，打车前往故宫，游玩2小时；中午在故宫附近用餐；下午参观天坛公园，游玩1.5小时；晚上返回酒店休息。\', \'spots\': [\'故宫\', \'天坛公园\']}, {\'day\': 2, \'content\': \'第2天（北京）：早上8:00乘坐地铁至颐和园，游玩2.5小时；中午在颐和园附近用餐；下午参观圆明园，游玩2小时；晚上返回酒店休息。\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第3天（北京）：早上9:00步行至国家博物馆，游玩2小时；中午在博物馆附近用餐；下午参观天安门广场，游玩1小时；傍晚返回酒店，准备返程。\', \'spots\': [\'国家博物馆\', \'天安门广场\']}]', '北京推荐：市中心区域酒店', '北京美食：烤鸭、炸酱面、豆汁焦圈', '1. 北京景点较多，建议使用地铁出行；2. 景点需提前预约门票；3. 注意天气变化，做好保暖或防晒措施', '2026-03-19 22:20:17', '[\'深度文化体验\', \'景点集中便于游览\', \'交通方便\', \'行程安排合理\']');
INSERT INTO `travel_plan` VALUES ('TP478f144593', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'故宫\', \'天坛公园\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'国家博物馆\', \'前门大街\']}]', '推荐住在市中心的酒店，方便出行，如王府井附近。', '尝试北京烤鸭、炸酱面、豆汁焦圈等特色美食。', '提前预订景点门票，避免排队；注意保暖，北京早晚温差较大。', '2026-03-12 15:22:54', NULL);
INSERT INTO `travel_plan` VALUES ('TP4b5bcfa428', 1, '武汉', 4, 3000, 'culturalExploration', '我想去安徽潜山玩，推荐一些好吃的', '[{\'day\': 1, \'content\': \'抵达武汉，参观黄鹤楼，感受历史文化。\', \'spot\': [\'黄鹤楼\']}, {\'day\': 2, \'content\': \'游览东湖绿道，体验自然风光，晚上品尝武汉热干面。\', \'spot\': [\'东湖绿道\']}, {\'day\': 3, \'content\': \'前往安徽潜山，参观天柱山景区，了解当地文化。\', \'spot\': [\'天柱山\']}, {\'day\': 4, \'content\': \'返回武汉，探访楚河汉街，品尝地道小吃。\', \'spot\': [\'楚河汉街\']}]', '推荐入住武汉市中心酒店，如武昌区或江岸区的经济型酒店，预算约200元/晚。', '推荐尝试热干面、豆皮、鸭脖、武昌鱼和潜山特色菜肴，如潜山豆腐、腊味煲等。', '提前规划好往返潜山的交通，注意天气变化，携带适合的衣物。', '2026-03-04 08:50:54', NULL);
INSERT INTO `travel_plan` VALUES ('TP4d85480282', 1, '长沙', 6, 3000, 'culturalExploration', '我想去长沙，并且经过上海', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'岳麓山\', \'湖南大学\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'橘子洲头\', \'湖南省博物馆\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'天心阁\', \'文和友\']}, {\'day\': 4, \'content\': \'第四天行程描述\', \'spots\': [\'岳王庙\', \'杜甫江阁\']}, {\'day\': 5, \'content\': \'第五天行程描述\', \'spots\': [\'IFS国金中心\', \'梅溪湖国际文化艺术中心\']}, {\'day\': 6, \'content\': \'第六天行程描述\', \'spots\': [\'长沙站\', \'返回上海\']}]', '推荐住在市中心的酒店，如五一广场附近，方便出行和体验城市文化。', '尝试长沙特色美食，如臭豆腐、口味虾、剁椒鱼头等。', '注意防蚊虫，携带轻便衣物，提前预订景点门票以节省时间。', '2026-03-12 20:21:46', NULL);
INSERT INTO `travel_plan` VALUES ('TP4f49d5d488', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'故宫\', \'天安门广场\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'长城\', \'798艺术区\']}]', '推荐住在市中心，方便游览景点，如王府井附近酒店。', '尝试北京烤鸭、炸酱面、豆汁焦圈等特色美食。', '注意天气变化，准备适合的衣物；提前预订景点门票以节省时间。', '2026-03-10 21:39:00', NULL);
INSERT INTO `travel_plan` VALUES ('TP4fa47615b7', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第1天（北京）：早上7:30从酒店出发，乘坐地铁2号线至天安门广场，游玩2小时；中午在附近品尝烤鸭；下午步行至故宫，游玩3小时；晚上前往王府井大街逛街吃饭。\', \'spots\': [\'天安门广场\', \'故宫\', \'王府井大街\']}, {\'day\': 2, \'content\': \'第2天（北京）：早上8:00从酒店出发，乘坐地铁4号线至颐和园，游玩3小时；中午在附近用餐；下午参观圆明园，游玩2小时；晚上返回酒店休息。\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第3天（北京）：早上9:00从酒店出发，乘坐公交至八达岭长城，游玩4小时；中午在景区内用餐；下午返回市区，参观首都博物馆，游玩2小时；晚上离开北京。\', \'spots\': [\'八达岭长城\', \'首都博物馆\']}]', '北京推荐：市中心区域酒店', '北京美食：烤鸭、炸酱面、豆汁焦圈', '1. 北京景点较分散，建议使用地铁或打车；2. 长城游玩注意安全；3. 提前预订门票节省时间', '2026-03-19 22:40:34', '[\'深度文化体验\', \'景点分布合理\', \'交通便捷\', \'预算控制得当\']');
INSERT INTO `travel_plan` VALUES ('TP51cc19f7bb', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'故宫\', \'天安门广场\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'长城\', \'国家博物馆\']}]', '推荐住在市中心，方便前往各个景点，如王府井附近酒店。', '尝试北京烤鸭、炸酱面、豆汁儿等特色美食。', '提前预订景点门票，避免排队；注意保暖，北京早晚温差较大。', '2026-03-10 21:45:41', NULL);
INSERT INTO `travel_plan` VALUES ('TP54e106e92a', 1, '武汉', 3, 3000, 'culturalExploration', '我想上海', '[{\'day\': 1, \'content\': \'第1天（武汉）：早上8:00酒店出发，步行10分钟至黄鹤楼，游玩1.5小时；中午步行至户部巷品尝小吃；傍晚步行至长江大桥观赏夜景。\', \'spots\': [\'黄鹤楼\', \'户部巷\', \'长江大桥\']}, {\'day\': 2, \'content\': \'第2天（武汉）：上午乘坐地铁4号线至东湖，骑行绿道2小时；下午参观武汉大学；晚上前往楚河汉街逛街吃饭。\', \'spots\': [\'东湖\', \'武汉大学\', \'楚河汉街\']}, {\'day\': 3, \'content\': \'第3天（武汉）：上午搭乘高铁至上海，抵达后前往外滩，步行游览；下午参观豫园和城隍庙，晚上在南京路购物用餐。\', \'spots\': [\'外滩\', \'豫园\', \'城隍庙\', \'南京路\']}]', '武汉推荐：楚河汉街附近酒店；上海推荐：外滩附近酒店', '武汉美食：热干面、三鲜豆皮、小龙虾；上海美食：小笼包、生煎、蟹粉汤包', '1. 武汉景点分散，尽量地铁出行；2. 上海交通发达，建议使用地铁；3. 注意天气变化，备好雨具', '2026-03-19 21:58:06', '[\'跨城市文化探索\', \'交通便捷高效\', \'美食与景点结合\', \'行程丰富多样\']');
INSERT INTO `travel_plan` VALUES ('TP554bb29cba', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'故宫\', \'天坛公园\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'长城\', \'颐和园\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'国家博物馆\', \'南锣鼓巷\']}]', '推荐住在市中心的酒店，方便游览景点。', '尝试北京烤鸭、炸酱面和豆汁焦圈等特色美食。', '提前预订景点门票，避免排队；注意保暖，北京早晚温差较大。', '2026-03-10 22:48:11', NULL);
INSERT INTO `travel_plan` VALUES ('TP55904d9197', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第1天（北京）：早上7:30酒店出发，步行15分钟至天安门广场，游玩2小时；随后步行至故宫，参观3小时；中午在故宫附近用餐；下午参观景山公园，傍晚返回酒店。\', \'spots\': [\'天安门广场\', \'故宫\', \'景山公园\']}, {\'day\': 2, \'content\': \'第2天（北京）：早上8:00乘坐地铁至八达岭长城，乘车1小时到达，游玩3小时；中午在长城附近用餐；下午参观居庸关，傍晚返回市区。\', \'spots\': [\'八达岭长城\', \'居庸关\']}, {\'day\': 3, \'content\': \'第3天（北京）：早上9:00前往颐和园，步行10分钟至门口，游玩2.5小时；中午在颐和园附近用餐；下午参观圆明园，傍晚返回酒店。\', \'spots\': [\'颐和园\', \'圆明园\']}]', '北京推荐：市中心或景点附近酒店', '北京美食：炸酱面、烤鸭、豆汁焦圈', '1. 北京景点多，建议使用地铁和打车结合出行；2. 颐和园和圆明园门票需提前预订；3. 冬季注意保暖', '2026-03-19 22:24:31', '[\'深度文化体验\', \'景点集中且交通便利\', \'经典历史景点全覆盖\', \'行程节奏适中\']');
INSERT INTO `travel_plan` VALUES ('TP59b239471e', 1, '上海', 3, 3000, 'culturalExploration', '我想去上海', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'外滩\', \'豫园\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'上海博物馆\', \'田子坊\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'南京路步行街\', \'上海科技馆\']}]', '推荐入住浦东新区的酒店，方便前往多个景点。', '尝试小笼包、生煎、本帮菜等特色美食。', '提前规划好交通路线，尽量使用地铁出行；注意保管随身物品。', '2026-03-12 20:00:15', NULL);
INSERT INTO `travel_plan` VALUES ('TP619ce1f606', 1, '武汉', 8, 3000, 'culturalExploration', '我想去去北京，然后再到长沙，最后返回北京', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'景点1\', \'景点2\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'景点3\']}]', '酒店推荐描述', '美食推荐描述', '旅行小贴士', '2026-03-12 20:30:22', NULL);
