INSERT INTO `travel_plan` VALUES ('TP65e1a2debc', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第一天（北京）：抵达北京，游览故宫、天安门广场\', \'spots\': [\'故宫\', \'天安门广场\']}, {\'day\': 2, \'content\': \'第二天（北京）：参观颐和园、圆明园\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第三天（北京）：游览八达岭长城、返回\', \'spots\': [\'八达岭长城\']}]', '北京推荐：北京7天酒店（市中心）', '北京美食：烤鸭、炸酱面、豆汁儿', '1. 北京地铁发达，建议使用交通卡；2. 八达岭长城较远，建议早出发', '2026-03-19 19:45:01', '[\'文化深度体验\', \'经典景点全覆盖\', \'交通便捷高效\', \'行程合理不紧张\']');
INSERT INTO `travel_plan` VALUES ('TP6809a694b8', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'故宫\', \'天安门广场\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'长城\', \'国家博物馆\']}]', '推荐住在市中心，方便出行，如王府井或西单附近。', '尝试北京烤鸭、炸酱面、豆汁焦圈等传统美食。', '提前预订景点门票，避免排队；注意保暖，北京早晚温差较大。', '2026-03-11 08:34:32', NULL);
INSERT INTO `travel_plan` VALUES ('TP683b45899f', 1, '上海', 3, 3000, 'culturalExploration', '我想去上海', '[{\'day\': 1, \'content\': \'第一天（上海）：抵达上海，游览外滩、南京路步行街\', \'spots\': [\'外滩\', \'南京路步行街\']}, {\'day\': 2, \'content\': \'第二天（上海）：参观上海博物馆、豫园\', \'spots\': [\'上海博物馆\', \'豫园\']}, {\'day\': 3, \'content\': \'第三天（上海）：游览田子坊、新天地\', \'spots\': [\'田子坊\', \'新天地\']}]', '上海推荐：上海浦东丽思卡尔顿酒店', '上海美食：小笼包、生煎、蟹粉汤包', '1. 上海地铁便捷，建议购买交通卡；2. 外滩夜景最佳，建议晚上前往', '2026-03-17 20:20:26', NULL);
INSERT INTO `travel_plan` VALUES ('TP69d56631bc', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第1天（北京）：早上7:30从酒店出发，乘坐地铁10号线至天安门广场，游玩2小时；随后步行至故宫，游玩3小时；中午在故宫附近用餐；下午参观景山公园，傍晚返回酒店。\', \'spots\': [\'天安门广场\', \'故宫\', \'景山公园\']}, {\'day\': 2, \'content\': \'第2天（北京）：早上8:00从酒店出发，乘坐地铁4号线至颐和园，游玩3小时；中午在颐和园附近用餐；下午参观圆明园，游玩2小时；晚上返回酒店。\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第3天（北京）：早上9:00从酒店出发，乘坐地铁13号线至八达岭长城，游玩3小时；中午在长城附近用餐；下午参观居庸关，傍晚返回酒店。\', \'spots\': [\'八达岭长城\', \'居庸关\']}]', '北京推荐：天安门或故宫附近酒店', '北京美食：烤鸭、炸酱面、豆汁焦圈', '1. 北京景点分散，建议多使用地铁出行；2. 颐和园和长城需提前购票；3. 夏季注意防晒，冬季注意保暖', '2026-03-19 22:37:55', '[\'深度文化体验\', \'景点集中便于游览\', \'交通便捷\', \'行程合理不紧张\']');
INSERT INTO `travel_plan` VALUES ('TP6cda3ddde9', 1, '长沙', 3, 3000, 'culturalExploration', '我想去长沙', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'岳麓山\', \'湖南大学\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'橘子洲头\', \'湖南省博物馆\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'天心阁\', \'文和友\']}]', '推荐住在市中心，方便出行，如五一广场附近酒店。', '必尝美食：臭豆腐、口味虾、剁椒鱼头、糖油粑粑。', '长沙天气多变，建议带雨具；注意饮食卫生，避免肠胃不适。', '2026-03-12 20:18:01', NULL);
INSERT INTO `travel_plan` VALUES ('TP718305d27c', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第一天（北京）：抵达北京，游览故宫、天安门广场\', \'spots\': [\'故宫\', \'天安门广场\']}, {\'day\': 2, \'content\': \'第二天（北京）：参观颐和园、圆明园\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第三天（北京）：游览长城、返回\', \'spots\': [\'八达岭长城\']}]', '北京推荐：北京7天酒店', '北京美食：烤鸭、炸酱面、豆汁儿', '1. 建议提前预订故宫门票；2. 长城游览需穿舒适的鞋子；3. 北京地铁发达，建议使用地铁出行', '2026-03-17 20:44:42', NULL);
INSERT INTO `travel_plan` VALUES ('TP729c01b7dc', 1, '湖南', 3, 3000, 'culturalExploration', '我想去湖南', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'张家界国家森林公园\', \'天门山\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'岳麓山\', \'湖南省博物馆\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'橘子洲头\', \'岳麓书院\']}]', '推荐住在长沙市的酒店，方便前往主要景点，性价比高。', '尝试湖南特色美食，如剁椒鱼头、口味虾、辣椒炒肉等。', '注意防蚊虫，携带适合的鞋子，湖南天气多变，建议带雨具。', '2026-03-11 08:24:48', NULL);
INSERT INTO `travel_plan` VALUES ('TP74b3a08074', 1, '上海/长沙', 6, 3000, 'culturalExploration', '我想去上海，然后再去长沙', '[{\'day\': 1, \'content\': \'第一天（上海）：抵达上海，游览外滩、南京路步行街\', \'spots\': [\'外滩\', \'南京路步行街\']}, {\'day\': 2, \'content\': \'第二天（上海）：参观上海博物馆、豫园\', \'spots\': [\'上海博物馆\', \'豫园\']}, {\'day\': 3, \'content\': \'第三天（上海）：前往杭州，游览西湖、灵隐寺\', \'spots\': [\'西湖\', \'灵隐寺\']}, {\'day\': 4, \'content\': \'第四天（长沙）：抵达长沙，游览岳麓山、橘子洲\', \'spots\': [\'岳麓山\', \'橘子洲\']}, {\'day\': 5, \'content\': \'第五天（长沙）：参观湖南省博物馆、天心阁\', \'spots\': [\'湖南省博物馆\', \'天心阁\']}, {\'day\': 6, \'content\': \'第六天（长沙）：自由活动，购买当地特产，返程\', \'spots\': [\'坡子街\', \'文和友\']}]', '上海推荐：上海酒店；长沙推荐：长沙酒店', '上海美食：小笼包、生煎；长沙美食：臭豆腐、茶颜悦色', '1. 上海到杭州高铁约1小时；2. 长沙景点集中，建议提前规划路线', '2026-03-12 20:57:45', NULL);
INSERT INTO `travel_plan` VALUES ('TP751057086c', 1, '武汉', 3, 3000, 'culturalExploration', '我想去武汉玩3天，主要想看黄鹤楼和东湖，喜欢吃当地小吃，希望住在地铁附近的舒适型酒店，预算大约3000元。', '[{\'day\': \'第1天\', \'content\': \'上午参观黄鹤楼，了解其历史和文化背景；下午前往东湖绿道骑行，欣赏湖景。\', \'spot\': \'黄鹤楼、东湖绿道\'}, {\'day\': \'第2天\', \'content\': \'全天游览武汉大学，感受校园文化和樱花景观；晚上品尝热干面等当地小吃。\', \'spot\': \'武汉大学、户部巷\'}, {\'day\': \'第3天\', \'content\': \'参观湖北省博物馆，了解楚文化；随后前往长江大桥步行或骑行，结束行程。\', \'spot\': \'湖北省博物馆、长江大桥\'}]', '地铁2号线附近舒适型酒店（如汉口火车站附近）', '热干面、豆皮、武昌鱼、鸭脖、汤包', '提前预订景点门票，避开节假日高峰；地铁出行方便；注意饮食卫生，尝试地道小吃。', '2026-03-04 08:41:54', NULL);
INSERT INTO `travel_plan` VALUES ('TP755782635d', 1, '武汉', 5, 3000, 'culturalExploration', '我想从长沙到北京', '[{\'day\': 1, \'content\': \'第一天（长沙）：抵达长沙，游览岳麓山、橘子洲\', \'spots\': [\'岳麓山\', \'橘子洲\']}, {\'day\': 2, \'content\': \'第二天（长沙）：品尝长沙美食，游览太平街、火宫殿\', \'spots\': [\'太平街\', \'火宫殿\']}, {\'day\': 3, \'content\': \'第三天（武汉）：从长沙前往武汉，游览黄鹤楼、东湖\', \'spots\': [\'黄鹤楼\', \'东湖\']}, {\'day\': 4, \'content\': \'第四天（武汉）：参观湖北省博物馆、长江大桥\', \'spots\': [\'湖北省博物馆\', \'长江大桥\']}, {\'day\': 5, \'content\': \'第五天（武汉）：自由活动，购买纪念品，返程\', \'spots\': [\'武汉长江大桥\']}]', '长沙推荐：长沙7天酒店；武汉推荐：武汉全季酒店', '长沙美食：臭豆腐、茶颜悦色；武汉美食：热干面、三鲜豆皮', '1. 长沙到武汉高铁约1.5小时；2. 武汉景点多，建议穿舒适的鞋子', '2026-03-12 21:06:51', NULL);
INSERT INTO `travel_plan` VALUES ('TP77462ca1d4', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'故宫\', \'天坛公园\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'长城\', \'颐和园\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'国家博物馆\', \'南锣鼓巷\']}]', '推荐位于市中心的经济型酒店，方便游览主要景点。', '尝试北京烤鸭、炸酱面和豆汁儿等特色美食。', '提前预订景点门票，避免排队；注意天气变化，准备适合的衣物。', '2026-03-10 21:39:14', NULL);
INSERT INTO `travel_plan` VALUES ('TP791558a4f4', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第一天（北京）：抵达北京，游览故宫、天坛\', \'spots\': [\'故宫\', \'天坛\']}, {\'day\': 2, \'content\': \'第二天（北京）：参观颐和园、圆明园\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第三天（北京）：游览长城、返回\', \'spots\': [\'八达岭长城\']}]', '北京推荐：北京京广中心酒店', '北京美食：烤鸭、炸酱面、豆汁焦圈', '1. 北京地铁覆盖广泛，建议使用交通卡；2. 长城需提前预订门票；3. 冬季注意保暖', '2026-03-17 20:57:06', '[\'文化体验丰富\', \'景点集中省时\', \'交通便捷\', \'适合深度游\']');
INSERT INTO `travel_plan` VALUES ('TP7a8c33416c', 1, '武汉', 6, 3000, 'culturalExploration', '我想去去长沙，经过北京', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'黄鹤楼\', \'东湖\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'湖北省博物馆\', \'古琴台\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'武汉长江大桥\', \'汉口江滩\']}, {\'day\': 4, \'content\': \'第四天行程描述\', \'spots\': [\'东湖听涛景区\', \'武汉大学\']}, {\'day\': 5, \'content\': \'第五天行程描述\', \'spots\': [\'晴川阁\', \'归元寺\']}, {\'day\': 6, \'content\': \'第六天行程描述\', \'spots\': [\'武汉长江大桥\', \'楚河汉街\']}]', '推荐选择市中心区域的经济型酒店，如武昌区或江汉路附近，方便出行且价格实惠。', '尝试热干面、豆皮、鸭脖等武汉特色小吃，推荐在户部巷或粮道街品尝。', '武汉夏季较热，注意防晒；公共交通发达，建议使用地铁和公交出行。', '2026-03-12 20:27:16', NULL);
