INSERT INTO `travel_plan` VALUES ('TP89d7b2bed9', 1, '随州', 3, 300, 'culturalExploration', '我想去随州', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'古银杏群落\', \'曾侯乙博物馆\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'擂鼓墩古墓群\', \'炎帝故里\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'随州白云山国家森林公园\']}]', '推荐住在市中心附近，方便前往各个景点。', '尝试随州的特色美食，如随州蜜枣、香菇炖鸡等。', '随州气候温和，适合四季旅游。提前预订景点门票，避免排队。', '2026-03-10 22:48:58', NULL);
