INSERT INTO `travel_plan` VALUES ('TP93944ec3ca', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第一天（北京）：抵达北京，游览天安门广场、故宫\', \'spots\': [\'天安门广场\', \'故宫\']}, {\'day\': 2, \'content\': \'第二天（北京）：参观颐和园、圆明园\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第三天（北京）：游览长城、返回\', \'spots\': [\'八达岭长城\']}]', '北京推荐：北京7天酒店', '北京美食：烤鸭、炸酱面、豆汁焦圈', '1. 北京地铁发达，建议使用交通卡；2. 长城建议穿舒适的鞋子；3. 提前预订门票避免排队', '2026-03-17 21:01:42', '[\'文化深度体验\', \'景点集中便于游览\', \'预算合理安排\', \'行程紧凑不浪费时间\']');
INSERT INTO `travel_plan` VALUES ('TP93f679d667', 1, '长沙', 6, 3000, 'culturalExploration', '我想去长沙，经过北京', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'天心阁\', \'岳麓山\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'湖南省博物馆\', \'橘子洲头\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'岳麓书院\', \'文庙\']}, {\'day\': 4, \'content\': \'第四天行程描述\', \'spots\': [\'烈士公园\', \'湖南省图书馆\']}, {\'day\': 5, \'content\': \'第五天行程描述\', \'spots\': [\'杜甫江阁\', \'火宫殿\']}, {\'day\': 6, \'content\': \'第六天行程描述\', \'spots\': [\'梅溪湖国际文化艺术中心\', \'滨江文化园\']}]', '推荐选择市中心区域的经济型酒店，如五一广场附近，方便出行且性价比高。', '必尝美食包括臭豆腐、口味虾、糖油粑粑和剁椒鱼头，建议去坡子街或太平老街品尝。', '提前预订门票以避免排队，注意防晒和携带身份证件。长沙地铁便捷，可优先使用公共交通。', '2026-03-12 20:27:39', NULL);
INSERT INTO `travel_plan` VALUES ('TP941c5ac511', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第1天（北京）：早上7:30从酒店出发，乘坐地铁2号线至天安门广场，游玩2小时；随后步行至故宫，参观3小时；中午在故宫附近用餐；下午参观景山公园，傍晚返回酒店休息。\', \'spots\': [\'天安门广场\', \'故宫\', \'景山公园\']}, {\'day\': 2, \'content\': \'第2天（北京）：早上8:00从酒店出发，乘坐公交至八达岭长城，游玩4小时；中午在长城脚下用餐；下午返回市区，参观中国国家博物馆，游览2小时；晚上在王府井逛街吃饭。\', \'spots\': [\'八达岭长城\', \'中国国家博物馆\', \'王府井\']}, {\'day\': 3, \'content\': \'第3天（北京）：早上9:00从酒店出发，乘坐地铁至颐和园，游玩3小时；中午在颐和园附近用餐；下午参观圆明园，游览2小时；傍晚返回酒店，准备返程。\', \'spots\': [\'颐和园\', \'圆明园\']}]', '北京推荐：市中心区域酒店', '北京美食：烤鸭、炸酱面、豆汁焦圈', '1. 北京景点较分散，建议使用地铁或打车；2. 颐和园和圆明园需提前预约门票；3. 冬季寒冷，注意保暖', '2026-03-19 22:33:02', '[\'深度文化体验\', \'景点分布合理\', \'交通便捷高效\', \'美食与历史结合\']');
INSERT INTO `travel_plan` VALUES ('TP9588c74615', 1, '安徽潜山玩', 4, 3000, 'culturalExploration', '我想去安徽潜山玩', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'天柱山风景区\', \'潜山博物馆\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'古皖文化园\', \'薛家岗遗址\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'痘姆陶艺村\', \'槎水温泉\']}, {\'day\': 4, \'content\': \'第四天行程描述\', \'spots\': [\'大别山国家森林公园\', \'潜山市老街\']}]', '推荐入住潜山市区的舒适型酒店，方便出行并体验当地生活。', '尝试潜山特色美食如腊八豆腐、潜山板鸭和石耳炖鸡。', '提前预订景点门票，注意山区天气变化，携带适合徒步的鞋子。', '2026-03-04 08:57:56', NULL);
INSERT INTO `travel_plan` VALUES ('TP95f11018e9', 1, '上海', 3, 3000, 'culturalExploration', '我想去上海', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'外滩\', \'豫园\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'上海博物馆\', \'田子坊\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'上海科技馆\', \'南京路步行街\']}]', '推荐入住人民广场附近酒店，方便出行且交通便利。', '尝试小笼包、生煎、本帮菜等特色美食。', '建议提前预约景点门票，避免排队；注意保管随身物品。', '2026-03-12 15:23:53', NULL);
INSERT INTO `travel_plan` VALUES ('TP999e0fd8cd', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第1天（北京）：早上7:30从酒店出发，乘坐地铁2号线至天安门广场，游玩2小时；中午在附近品尝烤鸭；下午步行至故宫，游玩3小时；晚上返回酒店休息。\', \'spots\': [\'天安门广场\', \'故宫\']}, {\'day\': 2, \'content\': \'第2天（北京）：早上8:00从酒店出发，乘坐公交至八达岭长城，乘车1小时，游玩4小时；中午在景区内用餐；下午返回市区，参观颐和园，游玩2.5小时；晚上返回酒店。\', \'spots\': [\'八达岭长城\', \'颐和园\']}, {\'day\': 3, \'content\': \'第3天（北京）：早上9:00从酒店出发，乘坐地铁至南锣鼓巷，游玩2小时；中午在附近品尝京味小吃；下午参观798艺术区，游玩2小时；傍晚返回酒店，准备返程。\', \'spots\': [\'南锣鼓巷\', \'798艺术区\']}]', '北京推荐：市中心区域酒店', '北京美食：烤鸭、炸酱面、豆汁焦圈', '1. 北京景点较远，建议多使用地铁和公交；2. 注意保暖，早晚温差大；3. 预订门票提前在线上完成', '2026-03-19 20:14:28', '[\'深度文化体验\', \'经典景点全覆盖\', \'交通便捷高效\', \'行程安排合理\']');
INSERT INTO `travel_plan` VALUES ('TP9c1b6c53cf', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第1天（北京）：早上7:30酒店出发，乘坐地铁1号线至天安门广场，游玩2小时；中午在附近品尝老北京炸酱面；下午步行至故宫，参观4小时；傍晚在王府井逛街吃饭。\', \'spots\': [\'天安门广场\', \'故宫\', \'王府井\']}, {\'day\': 2, \'content\': \'第2天（北京）：早上8:00酒店出发，乘坐地铁4号线至颐和园，游玩3小时；中午在公园内用餐；下午参观圆明园，游玩2小时；晚上返回市区在后海体验夜生活。\', \'spots\': [\'颐和园\', \'圆明园\', \'后海\']}, {\'day\': 3, \'content\': \'第3天（北京）：早上9:00酒店出发，乘坐公交至八达岭长城，游览3小时；中午在景区附近用餐；下午参观居庸关长城，游玩2小时；傍晚返回市区结束行程。\', \'spots\': [\'八达岭长城\', \'居庸关长城\']}]', '北京推荐：天安门或故宫附近酒店', '北京美食：炸酱面、烤鸭、豆汁焦圈', '1. 北京景点较多，建议使用地铁和公交出行；2. 长城天气多变，注意防风保暖；3. 提前预订门票避免排队', '2026-03-19 22:44:07', '[\'深度文化体验\', \'经典景点全覆盖\', \'交通便捷合理\', \'行程节奏舒适\']');
INSERT INTO `travel_plan` VALUES ('TPa2ec2cc576', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'故宫\', \'天坛公园\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'长城\', \'国家博物馆\']}]', '推荐住在市中心的酒店，方便出行。', '尝试北京烤鸭、炸酱面和豆汁焦圈等特色美食。', '提前预订景点门票，避免排队；注意保暖，北京早晚温差大。', '2026-03-11 08:31:02', NULL);
INSERT INTO `travel_plan` VALUES ('TPa5da5ad86a', 1, '北京', 5, 3000, 'culturalExploration', '我要去北京', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'故宫\', \'天坛公园\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'长城\', \'八达岭\']}, {\'day\': 4, \'content\': \'第四天行程描述\', \'spots\': [\'国家博物馆\', \'798艺术区\']}, {\'day\': 5, \'content\': \'第五天行程描述\', \'spots\': [\'南锣鼓巷\', \'前门大街\']}]', '推荐住在市中心，方便游览景点，如王府井或西单附近。', '尝试北京烤鸭、炸酱面、豆汁儿等特色美食。', '提前预订景点门票，避免排队；注意天气变化，准备适合的衣物。', '2026-03-04 17:37:41', NULL);
INSERT INTO `travel_plan` VALUES ('TPa5f7faeb3e', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第1天（北京）：早上7:30酒店出发，乘坐地铁2号线至天安门广场，游玩2小时；中午在附近品尝烤鸭；下午步行至故宫，游玩3小时；傍晚前往景山公园观赏故宫全景。\', \'spots\': [\'天安门广场\', \'故宫\', \'景山公园\']}, {\'day\': 2, \'content\': \'第2天（北京）：早上8:00酒店出发，乘坐公交至八达岭长城，游玩4小时；中午在长城脚下用餐；下午返回市区，参观中国国家博物馆，游玩2小时。\', \'spots\': [\'八达岭长城\', \'中国国家博物馆\']}, {\'day\': 3, \'content\': \'第3天（北京）：早上9:00酒店出发，乘坐地铁至颐和园，游玩3小时；中午在附近用餐；下午参观圆明园，游玩2小时；傍晚返回酒店休息。\', \'spots\': [\'颐和园\', \'圆明园\']}]', '北京推荐：天安门或故宫附近酒店', '北京美食：烤鸭、炸酱面、豆汁焦圈', '1. 北京景点较分散，建议多使用地铁；2. 颐和园和圆明园需提前预约门票；3. 夏季注意防晒，冬季注意保暖', '2026-03-19 22:43:53', '[\'深度文化体验\', \'经典景点全覆盖\', \'交通便捷高效\', \'行程合理不紧张\']');
INSERT INTO `travel_plan` VALUES ('TPad39bac2db', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第1天（北京）：早上7:30从酒店出发，乘坐地铁2号线至天安门广场，游玩2小时；中午在附近品尝炸酱面；下午步行至故宫，参观4小时；晚上前往王府井逛街吃饭。\', \'spots\': [\'天安门广场\', \'故宫\', \'王府井\']}, {\'day\': 2, \'content\': \'第2天（北京）：早上8:00从酒店出发，打车至八达岭长城，游览3小时；中午在景区附近用餐；下午返回市区，参观颐和园，游玩2.5小时；晚上前往后海酒吧街体验夜生活。\', \'spots\': [\'八达岭长城\', \'颐和园\', \'后海\']}, {\'day\': 3, \'content\': \'第3天（北京）：早上9:00从酒店出发，乘坐地铁至国家博物馆，参观3小时；中午在附近用餐；下午前往南锣鼓巷购物，游玩2小时；傍晚打车返回酒店，结束行程。\', \'spots\': [\'国家博物馆\', \'南锣鼓巷\']}]', '北京推荐：故宫附近酒店', '北京美食：炸酱面、烤鸭、豆汁焦圈', '1. 北京景点较分散，建议使用地铁或打车；2. 颐和园和故宫人较多，早起可避免拥挤；3. 注意保暖，北京早晚温差较大', '2026-03-19 22:43:43', '[\'深度文化体验\', \'景点集中便于游览\', \'美食丰富多样\', \'交通便捷\']');
INSERT INTO `travel_plan` VALUES ('TPaedbea3955', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第一天（北京）：抵达北京，游览天安门广场、故宫\', \'spots\': [\'天安门广场\', \'故宫\']}, {\'day\': 2, \'content\': \'第二天（北京）：参观颐和园、圆明园\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第三天（北京）：游览八达岭长城、返回\', \'spots\': [\'八达岭长城\']}]', '北京推荐：北京首都机场希尔顿欢朋酒店', '北京美食：烤鸭、炸酱面、豆汁焦圈', '1. 建议提前预约故宫门票；2. 北京地铁发达，建议使用地铁出行；3. 长城景区较大，建议穿舒适的鞋子', '2026-03-17 21:03:59', '[\'文化体验丰富\', \'景点集中便于游览\', \'交通便捷\', \'行程紧凑合理\']');
INSERT INTO `travel_plan` VALUES ('TPb102ee2dcd', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第1天（北京）：早上7:30从酒店出发，步行15分钟至天安门广场，游玩2小时；随后参观故宫，游览3.5小时；中午在故宫附近用餐；下午前往景山公园，登高俯瞰故宫全景，游玩1小时。\', \'spots\': [\'天安门广场\', \'故宫\', \'景山公园\']}, {\'day\': 2, \'content\': \'第2天（北京）：早上8:00从酒店出发，乘坐地铁4号线至颐和园，游玩3小时；中午在颐和园附近用餐；下午参观圆明园，游览2小时；傍晚返回酒店休息。\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第3天（北京）：早上9:00从酒店出发，乘坐公交至八达岭长城，乘车1小时，游玩4小时；中午在长城附近用餐；下午返回市区，参观国家博物馆，游览2小时；晚上返程。\', \'spots\': [\'八达岭长城\', \'国家博物馆\']}]', '北京推荐：市中心区域酒店，如王府井或前门附近', '北京美食：烤鸭、炸酱面、豆汁焦圈、糖葫芦', '1. 北京景点较分散，建议多使用地铁；2. 长城天气变化大，注意保暖；3. 提前预约博物馆门票', '2026-03-19 22:21:15', '[\'深度文化体验\', \'经典景点全覆盖\', \'交通便利\', \'行程节奏合理\']');
INSERT INTO `travel_plan` VALUES ('TPb1463c355f', 1, '菏泽', 3, 300, 'culturalExploration', '我想去菏泽', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'曹州牡丹园\', \'曹县古文化街\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'水泊梁山\', \'东明黄河故道\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'菏泽博物馆\', \'巨野书画院\']}]', '推荐入住菏泽市中心的经济型酒店，方便出行且价格实惠。', '尝试菏泽特色美食如曹州烧饼、郓城驴肉火烧和单县羊肉汤。', '菏泽气候温和，建议携带适合户外活动的衣物。提前预订景点门票以节省时间。', '2026-03-10 22:50:33', NULL);
INSERT INTO `travel_plan` VALUES ('TPb973813298', 1, '上海', 5, 3000, 'culturalExploration', '我想去上海', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'外滩\', \'南京路步行街\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'豫园\', \'城隍庙\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'上海博物馆\', \'人民广场\']}, {\'day\': 4, \'content\': \'第四天行程描述\', \'spots\': [\'田子坊\', \'新天地\']}, {\'day\': 5, \'content\': \'第五天行程描述\', \'spots\': [\'上海科技馆\', \'陆家嘴\']}]', '推荐入住市中心的酒店，方便游览主要景点。', '尝试上海小笼包、生煎和本帮菜，如红烧肉和腌笃鲜。', '尽量使用公共交通，避免高峰时段出行；注意保管个人财物。', '2026-03-12 20:06:15', NULL);
INSERT INTO `travel_plan` VALUES ('TPbb5ccf97d7', 1, '武汉', 3, 3000, 'culturalExploration', 'I want to visit Wuhan for 3 days, mainly want to see Yellow Crane Tower and East Lake, enjoy local snacks, hope to stay in a comfortable hotel near the subway, budget about 3000 yuan.', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'黄鹤楼\', \'户部巷\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'东湖风景区\', \'湖北省博物馆\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'长江大桥\', \'楚河汉街\']}]', '推荐入住位于地铁附近、交通便利的舒适型酒店。', '尝试热干面、豆皮、武昌鱼等当地特色小吃。', '提前预订景点门票，避免排队；注意天气变化，准备适合的衣物。', '2026-03-10 21:38:41', NULL);
INSERT INTO `travel_plan` VALUES ('TPbbeecb7ee8', 1, '长沙/北京', 5, 3000, 'culturalExploration', '我想去长沙，然后再去北京', '[{\'day\': 1, \'content\': \'第1天（长沙）：抵达长沙，游览岳麓山、橘子洲\', \'spots\': [\'岳麓山\', \'橘子洲\']}, {\'day\': 2, \'content\': \'第2天（长沙）：参观湖南省博物馆，品尝长沙特色美食\', \'spots\': [\'湖南省博物馆\']}, {\'day\': 3, \'content\': \'第3天（长沙）：从长沙前往北京，抵达后游览故宫、天坛\', \'spots\': [\'故宫\', \'天坛\']}, {\'day\': 4, \'content\': \'第4天（北京）：参观颐和园、圆明园，体验老北京文化\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 5, \'content\': \'第5天（北京）：游览八达岭长城，结束行程\', \'spots\': [\'八达岭长城\']}]', '长沙推荐：长沙7天酒店；北京推荐：北京全季酒店', '长沙美食：臭豆腐、茶颜悦色；北京美食：烤鸭、豆汁焦圈', '1. 长沙到北京高铁约5小时；2. 北京景点较多，建议提前购票', '2026-03-12 21:07:26', NULL);
INSERT INTO `travel_plan` VALUES ('TPbd331887ac', 1, '上海/长沙', 6, 3000, 'culturalExploration', '我想去上海，然后再去长沙', '[{\'day\': 1, \'content\': \'第一天（上海）：抵达上海，游览外滩、南京路\', \'spots\': [\'外滩\', \'南京路\']}, {\'day\': 2, \'content\': \'第二天（上海）：参观上海博物馆、豫园\', \'spots\': [\'上海博物馆\', \'豫园\']}, {\'day\': 3, \'content\': \'第三天（上海）：前往杭州，游览西湖、灵隐寺\', \'spots\': [\'西湖\', \'灵隐寺\']}, {\'day\': 4, \'content\': \'第四天（长沙）：抵达长沙，游览岳麓山、橘子洲\', \'spots\': [\'岳麓山\', \'橘子洲\']}, {\'day\': 5, \'content\': \'第五天（长沙）：参观湖南省博物馆、文庙\', \'spots\': [\'湖南省博物馆\', \'文庙\']}, {\'day\': 6, \'content\': \'第六天（长沙）：自由活动，购买当地特产，返程\', \'spots\': []}]', '上海推荐：XX酒店；长沙推荐：XX酒店', '上海美食：小笼包、生煎；长沙美食：臭豆腐、茶颜悦色', '1. 上海到长沙高铁约5小时；2. 长沙景点集中，建议多步行', '2026-03-12 20:56:06', NULL);
INSERT INTO `travel_plan` VALUES ('TPbf1b0d12b4', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第1天（北京）：早上7:30酒店出发，乘坐地铁1号线至天安门广场，游玩2小时；中午在附近品尝炸酱面；下午步行至故宫，游玩3小时；傍晚前往景山公园观赏故宫全景。\', \'spots\': [\'天安门广场\', \'故宫\', \'景山公园\']}, {\'day\': 2, \'content\': \'第2天（北京）：早上8:00酒店出发，乘坐公交126路至颐和园，游玩3小时；中午在颐和园附近用餐；下午参观圆明园，游玩2小时；晚上返回酒店休息。\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第3天（北京）：早上9:00酒店出发，乘坐地铁4号线至国家博物馆，游玩2.5小时；中午在附近用餐；下午步行至天坛公园，游玩2小时；傍晚返回酒店并结束行程。\', \'spots\': [\'国家博物馆\', \'天坛公园\']}]', '北京推荐：天安门或故宫附近酒店', '北京美食：炸酱面、烤鸭、豆汁焦圈', '1. 北京景点多且分散，建议使用地铁和公交；2. 预订景点门票可提前在线购买；3. 注意保暖和防晒', '2026-03-19 20:12:51', '[\'深度文化体验\', \'景点集中便于游览\', \'交通便捷\', \'预算合理\']');
INSERT INTO `travel_plan` VALUES ('TPc226833928', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第1天（北京）：早上7:30从酒店出发，乘坐地铁1号线至天安门广场，游玩2小时；中午在附近品尝炸酱面；下午步行至故宫，游玩3小时；晚上前往王府井逛街吃饭。\', \'spots\': [\'天安门广场\', \'故宫\', \'王府井\']}, {\'day\': 2, \'content\': \'第2天（北京）：早上8:00从酒店出发，乘坐地铁4号线至颐和园，游玩3小时；中午在颐和园附近用餐；下午参观圆明园，游玩2小时；晚上返回酒店休息。\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第3天（北京）：早上9:00从酒店出发，乘坐地铁2号线至八达岭长城，游玩3小时；中午在景区附近用餐；下午返回市区，参观国家博物馆，游玩2小时；晚上返程。\', \'spots\': [\'八达岭长城\', \'国家博物馆\']}]', '北京推荐：市中心便捷出行的酒店', '北京美食：炸酱面、烤鸭、豆汁焦圈', '1. 北京景点较分散，建议多使用地铁；2. 颐和园和长城需提前预约；3. 夏季注意防晒，冬季注意保暖', '2026-03-19 22:36:58', '[\'深度文化体验\', \'交通便捷高效\', \'景点集中合理\', \'行程轻松舒适\']');
INSERT INTO `travel_plan` VALUES ('TPc5c70088f9', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第一天（北京）：抵达北京，游览故宫、天安门广场\', \'spots\': [\'故宫\', \'天安门广场\']}, {\'day\': 2, \'content\': \'第二天（北京）：参观颐和园、圆明园\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第三天（北京）：游览八达岭长城、返回\', \'spots\': [\'八达岭长城\']}]', '北京推荐：北京7天酒店', '北京美食：烤鸭、炸酱面、豆汁焦圈', '1. 北京地铁覆盖广泛，建议使用交通卡；2. 颐和园和圆明园距离较远，建议打车或包车；3. 八达岭长城需提前预约门票', '2026-03-17 21:02:52', '[\'文化深度体验\', \'景点集中高效\', \'交通便利省心\', \'适合历史爱好者\']');
INSERT INTO `travel_plan` VALUES ('TPd0f6576f52', 1, '北京', 6, 3000, 'culturalExploration', '我想先去北京，然后再到长沙', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'故宫\', \'天坛公园\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'八达岭长城\', \'居庸关\']}, {\'day\': 4, \'content\': \'第四天行程描述\', \'spots\': [\'国家博物馆\', \'南锣鼓巷\']}, {\'day\': 5, \'content\': \'第五天行程描述\', \'spots\': [\'景山公园\', \'什刹海\']}, {\'day\': 6, \'content\': \'第六天行程描述\', \'spots\': [\'奥林匹克公园\', \'鸟巢\']}]', '推荐入住市中心区域的经济型酒店，方便游览主要景点。', '尝试北京烤鸭、炸酱面、豆汁焦圈等特色美食。', '提前预订景点门票，避免排队；注意保暖，北京早晚温差较大。', '2026-03-12 20:37:17', NULL);
INSERT INTO `travel_plan` VALUES ('TPd17fdc5f0c', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第一天（北京）：游览故宫、天安门广场\', \'spots\': [\'故宫\', \'天安门广场\']}, {\'day\': 2, \'content\': \'第二天（北京）：参观长城、颐和园\', \'spots\': [\'八达岭长城\', \'颐和园\']}, {\'day\': 3, \'content\': \'第三天（北京）：游览798艺术区、奥林匹克公园\', \'spots\': [\'798艺术区\', \'奥林匹克公园\']}]', '北京推荐：北京京伦饭店；如需其他区域，可提供更具体建议', '北京美食：烤鸭、炸酱面、豆汁焦圈', '1. 北京地铁覆盖广泛，建议使用交通卡；2. 长城景区较大，建议穿舒适鞋子；3. 烤鸭需提前预约', '2026-03-17 21:03:28', '[\'文化体验丰富\', \'景点分布合理\', \'交通便捷\', \'适合深度游\']');
