INSERT INTO `travel_plan` VALUES ('TPd4011a0402', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第一天（北京）：抵达北京，游览故宫、天安门广场\', \'spots\': [\'故宫\', \'天安门广场\']}, {\'day\': 2, \'content\': \'第二天（北京）：参观颐和园、圆明园\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第三天（北京）：游览长城、返回\', \'spots\': [\'八达岭长城\']}]', '北京推荐：北京京仪大酒店', '北京美食：烤鸭、炸酱面、豆汁焦圈', '1. 北京地铁发达，建议使用交通卡；2. 长城景区较大，建议穿舒适的鞋子', '2026-03-19 19:55:54', '[\'文化探索丰富\', \'景点集中便捷\', \'历史底蕴深厚\', \'行程节奏合理\']');
INSERT INTO `travel_plan` VALUES ('TPd46064893d', 1, '火星', 3, 3000, 'culturalExploration', '我想去火星', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'火星表面探索\', \'红色峡谷\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'极地冰冠\', \'古代遗迹\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'火星博物馆\', \'太空港\']}]', '火星度假酒店，提供舒适住宿和天文观测设施。', '火星特色美食包括营养棒、太空蔬菜和合成肉。', '请确保携带足够的氧气供应，并遵守火星环境保护规定。', '2026-03-11 08:36:00', NULL);
INSERT INTO `travel_plan` VALUES ('TPd826280727', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第一天（北京）：抵达北京，游览天安门广场、故宫\', \'spots\': [\'天安门广场\', \'故宫\']}, {\'day\': 2, \'content\': \'第二天（北京）：参观颐和园、圆明园\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第三天（北京）：游览长城（八达岭段）、返回\', \'spots\': [\'八达岭长城\']}]', '北京推荐：北京7天酒店（市中心）', '北京美食：烤鸭、炸酱面、豆汁焦圈', '1. 长城建议提前购票；2. 北京地铁发达，可多利用；3. 注意保暖', '2026-03-19 19:49:24', '[\'文化探索丰富\', \'景点集中省时\', \'交通便捷\', \'预算合理\']');
INSERT INTO `travel_plan` VALUES ('TPda24aea6c0', 1, '武汉', 3, 3000, 'culturalExploration', 'I want to visit Wuhan for 3 days, mainly want to see Yellow Crane Tower and East Lake, enjoy local snacks, hope to stay in a comfortable hotel near the subway, budget about 3000 yuan.', '[{\'day\': 1, \'content\': \'第一天（武汉）：抵达武汉，游览黄鹤楼、长江大桥\', \'spots\': [\'黄鹤楼\', \'长江大桥\']}, {\'day\': 2, \'content\': \'第二天（武汉）：游览东湖风景区、湖北省博物馆\', \'spots\': [\'东湖风景区\', \'湖北省博物馆\']}, {\'day\': 3, \'content\': \'第三天（武汉）：品尝武汉小吃，自由活动或购物\', \'spots\': [\'户部巷\', \'江汉路\']}]', '武汉推荐：武汉全季酒店（近地铁）', '武汉美食：热干面、豆皮、鸭脖', '1. 武汉景点之间交通便利，建议使用地铁；2. 带好舒适鞋子，步行较多；3. 小吃街如户部巷和江汉路是必去的', '2026-03-12 21:05:42', NULL);
INSERT INTO `travel_plan` VALUES ('TPda56717037', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'故宫\', \'天坛公园\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'长城\', \'国家博物馆\']}]', '推荐住在市中心的酒店，方便出行，如王府井附近。', '尝试北京烤鸭、炸酱面、豆汁儿等特色美食。', '提前预订景点门票，避免排队；注意保暖，北京早晚温差较大。', '2026-03-11 08:30:45', NULL);
INSERT INTO `travel_plan` VALUES ('TPdda900da84', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第1天（北京）：早上7:30酒店出发，乘坐地铁2号线至天安门广场，游玩2小时；随后步行至故宫，参观4小时；中午在故宫附近用餐；下午前往景山公园登高，傍晚返回酒店。\', \'spots\': [\'天安门广场\', \'故宫\', \'景山公园\']}, {\'day\': 2, \'content\': \'第2天（北京）：早上8:00酒店出发，乘坐地铁4号线至颐和园，游玩3小时；中午在颐和园附近用餐；下午参观圆明园，游览2小时；晚上返回酒店休息。\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第3天（北京）：早上9:00酒店出发，乘坐地铁10号线至国家博物馆，参观3小时；中午在博物馆附近用餐；下午前往王府井大街购物逛街，游览2小时；傍晚返回酒店并结束行程。\', \'spots\': [\'国家博物馆\', \'王府井大街\']}]', '北京推荐：市中心区域酒店', '北京美食：烤鸭、炸酱面、豆汁焦圈', '1. 北京景点多为步行或地铁，建议购买交通卡；2. 预计人流较多，注意保管随身物品；3. 空气干燥，建议携带保湿用品', '2026-03-19 22:35:20', '[\'深度文化体验\', \'景点集中便于游览\', \'交通便捷高效\', \'合理预算安排\']');
INSERT INTO `travel_plan` VALUES ('TPdf8df80dff', 1, '上海', 3, 3000, 'culturalExploration', '我想去上海', '[{\'day\': 1, \'content\': \'第1天（上海）：早上8:00酒店出发，步行15分钟至外滩，游玩2小时；中午步行至南京路步行街用餐；下午参观上海博物馆；晚上前往豫园和城隍庙体验传统文化。\', \'spots\': [\'外滩\', \'南京路步行街\', \'上海博物馆\', \'豫园\', \'城隍庙\']}, {\'day\': 2, \'content\': \'第2天（上海）：早上9:00乘坐地铁1号线至田子坊，游玩2小时；中午在田子坊附近用餐；下午参观思南公馆，感受海派文化；傍晚步行至新天地购物休闲。\', \'spots\': [\'田子坊\', \'思南公馆\', \'新天地\']}, {\'day\': 3, \'content\': \'第3天（上海）：早上8:30乘坐地铁2号线至朱家角古镇，游玩3小时；中午在古镇用餐；下午返回上海，参观上海老街；晚上在人民广场附近休息。\', \'spots\': [\'朱家角古镇\', \'上海老街\', \'人民广场\']}]', '上海推荐：外滩或南京路附近酒店', '上海美食：小笼包、生煎、蟹粉汤包、本帮菜', '1. 上海地铁覆盖广泛，建议使用交通卡；2. 夏季注意防晒，冬季保暖；3. 部分景点需提前预约', '2026-03-19 22:35:55', '[\'深入体验上海历史文化\', \'涵盖经典景点与特色街区\', \'交通便捷适合步行或地铁\', \'美食与文化结合丰富\']');
INSERT INTO `travel_plan` VALUES ('TPe27e9bc7f0', 1, '长沙', 6, 3000, 'culturalExploration', '我想去长沙，中间要经过北京', '[{\'day\': 1, \'content\': \'第一天：从北京出发，抵达长沙，入住酒店，休息调整时差\', \'spots\': []}, {\'day\': 2, \'content\': \'第二天：游览岳麓山、橘子洲头，感受长沙历史文化\', \'spots\': [\'岳麓山\', \'橘子洲头\']}, {\'day\': 3, \'content\': \'第三天：参观湖南省博物馆，了解湖南历史与文化\', \'spots\': [\'湖南省博物馆\']}, {\'day\': 4, \'content\': \'第四天：前往张家界，欣赏自然风光（若预算允许）或在长沙周边游玩\', \'spots\': []}, {\'day\': 5, \'content\': \'第五天：在长沙自由活动，尝试当地小吃，如臭豆腐、口味虾等\', \'spots\': []}, {\'day\': 6, \'content\': \'第六天：返程，结束愉快的长沙文化之旅\', \'spots\': []}]', '推荐选择市中心交通便利的经济型酒店，方便出行和体验城市生活。', '长沙特色美食包括臭豆腐、口味虾、剁椒鱼头、米粉等，建议尝试地道小吃街。', '提前预订车票和酒店，注意天气变化，携带适合的衣物。', '2026-03-12 20:28:54', NULL);
INSERT INTO `travel_plan` VALUES ('TPe2c46158d1', 1, '武汉', 3, 3000, 'culturalExploration', 'I want to visit Wuhan for 3 days, mainly want to see Yellow Crane Tower and East Lake, enjoy local snacks, hope to stay in a comfortable hotel near the subway, budget about 3000 yuan.', '[{\'day\': 1, \'content\': \'第一天（武汉）：抵达武汉，游览黄鹤楼\', \'spots\': [\'黄鹤楼\']}, {\'day\': 2, \'content\': \'第二天（武汉）：参观东湖景区，品尝当地小吃\', \'spots\': [\'东湖\']}, {\'day\': 3, \'content\': \'第三天（武汉）：游览湖北省博物馆，购物或自由活动\', \'spots\': [\'湖北省博物馆\']}]', '武汉推荐：武汉光谷凯莱酒店（近地铁），舒适且交通便利', '武汉美食：热干面、豆皮、武昌鱼、汤包', '1. 武汉景点之间有地铁连接，方便出行；2. 建议提前预订酒店以确保位置和价格合理；3. 小吃街如户部巷是体验本地风味的好地方', '2026-03-17 20:19:30', NULL);
INSERT INTO `travel_plan` VALUES ('TPe30a4cecf0', 1, '北京', 6, 3000, 'culturalExploration', '我想去北京，然后再去长沙', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'故宫\', \'天坛公园\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'八达岭长城\', \'颐和园\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'圆明园\', \'国家博物馆\']}, {\'day\': 4, \'content\': \'第四天行程描述\', \'spots\': [\'南锣鼓巷\', \'后海\']}, {\'day\': 5, \'content\': \'第五天行程描述\', \'spots\': [\'鸟巢\', \'水立方\']}, {\'day\': 6, \'content\': \'第六天行程描述\', \'spots\': [\'景山公园\', \'王府井大街\']}]', '推荐住在市中心的酒店，方便出行并靠近景点。', '尝试北京烤鸭、炸酱面、豆汁儿等特色美食。', '提前预订景点门票，避免排队；注意保暖，北京早晚温差大。', '2026-03-12 20:26:55', NULL);
INSERT INTO `travel_plan` VALUES ('TPe388fbf0c7', 1, '上海', 4, 3000, 'culturalExploration', '我想去上海', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'外滩\', \'南京路步行街\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'豫园\', \'城隍庙\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'上海博物馆\', \'田子坊\']}, {\'day\': 4, \'content\': \'第四天行程描述\', \'spots\': [\'东方明珠塔\', \'上海科技馆\']}]', '推荐入住市中心的酒店，方便出行并感受上海的城市氛围。', '尝试上海小笼包、生煎、蟹粉汤包等特色美食。', '提前预订景点门票，避开高峰时段，注意保管随身物品。', '2026-03-12 20:12:53', NULL);
INSERT INTO `travel_plan` VALUES ('TPe48b99f326', 1, '上海', 3, 3000, 'culturalExploration', '我想去上海', '[{\'day\': 1, \'content\': \'第1天（上海）：早上8:00酒店出发，步行15分钟至外滩，游玩2小时；中午步行至南京路步行街用餐；下午乘坐地铁1号线至豫园，游览1.5小时；傍晚步行至城隍庙品尝小吃。\', \'spots\': [\'外滩\', \'南京路步行街\', \'豫园\', \'城隍庙\']}, {\'day\': 2, \'content\': \'第2天（上海）：早上9:00乘坐地铁2号线至上海博物馆，参观2小时；中午在博物馆附近用餐；下午乘坐地铁10号线至田子坊，游览1.5小时；傍晚步行至新天地逛街吃饭。\', \'spots\': [\'上海博物馆\', \'田子坊\', \'新天地\']}, {\'day\': 3, \'content\': \'第3天（上海）：早上10:00乘坐地铁4号线至朱家角古镇，游览2小时；中午在古镇用餐；下午乘坐高铁返回，结束行程。\', \'spots\': [\'朱家角古镇\']}]', '上海推荐：外滩或南京路附近酒店', '上海美食：小笼包、生煎、本帮菜、汤圆', '1. 上海地铁覆盖广泛，建议使用交通卡；2. 部分景点需提前预约；3. 夏季注意防暑降温', '2026-03-19 22:00:44', '[\'深度文化体验\', \'交通便捷高效\', \'美食丰富多样\', \'景点分布合理\']');
