INSERT INTO `travel_plan` VALUES ('TPe6a002aa82', 1, '北京', 5, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'故宫\', \'天坛公园\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'八达岭长城\', \'居庸关\']}, {\'day\': 4, \'content\': \'第四天行程描述\', \'spots\': [\'国家博物馆\', \'南锣鼓巷\']}, {\'day\': 5, \'content\': \'第五天行程描述\', \'spots\': [\'景山公园\', \'王府井大街\']}]', '推荐选择市中心区域的经济型酒店，方便出行并节省交通费用。', '尝试北京烤鸭、炸酱面、豆汁焦圈等传统美食，建议前往老字号餐厅体验。', '提前预订景点门票以避免排队，注意天气变化，携带适合的衣物。', '2026-03-12 20:03:26', NULL);
INSERT INTO `travel_plan` VALUES ('TPe6c16321e9', 1, '武汉', 5, 3000, 'culturalExploration', '我想从长沙到武汉', '[{\'day\': 1, \'content\': \'第一天（长沙）：抵达长沙，游览岳麓山、橘子洲\', \'spots\': [\'岳麓山\', \'橘子洲\']}, {\'day\': 2, \'content\': \'第二天（长沙）：品尝长沙美食，游览天心阁、太平街\', \'spots\': [\'天心阁\', \'太平街\']}, {\'day\': 3, \'content\': \'第三天（武汉）：从长沙前往武汉，游览黄鹤楼、东湖\', \'spots\': [\'黄鹤楼\', \'东湖\']}, {\'day\': 4, \'content\': \'第四天（武汉）：参观湖北省博物馆、户部巷\', \'spots\': [\'湖北省博物馆\', \'户部巷\']}, {\'day\': 5, \'content\': \'第五天（武汉）：自由活动，购买纪念品，返程\', \'spots\': []}]', '长沙推荐：长沙7天酒店；武汉推荐：武汉全季酒店', '长沙美食：臭豆腐、茶颜悦色；武汉美食：热干面、三鲜豆皮', '1. 长沙到武汉高铁约1.5小时；2. 武汉景点多，建议穿舒适的鞋子', '2026-03-12 21:06:09', NULL);
INSERT INTO `travel_plan` VALUES ('TPe6dae0e449', 1, '长沙', 5, 3000, 'culturalExploration', '我想去长沙', '[{\'day\': 1, \'content\': \'第一天（长沙）：抵达长沙，游览岳麓山、爱晚亭\', \'spots\': [\'岳麓山\', \'爱晚亭\']}, {\'day\': 2, \'content\': \'第二天（长沙）：参观湖南省博物馆、橘子洲\', \'spots\': [\'湖南省博物馆\', \'橘子洲\']}, {\'day\': 3, \'content\': \'第三天（长沙）：游览天心阁、太平街\', \'spots\': [\'天心阁\', \'太平街\']}, {\'day\': 4, \'content\': \'第四天（长沙）：前往张家界，游览张家界国家森林公园\', \'spots\': [\'张家界国家森林公园\']}, {\'day\': 5, \'content\': \'第五天（长沙）：返回长沙，自由活动，结束行程\', \'spots\': []}]', '长沙推荐：长沙君悦酒店；张家界推荐：张家界华天酒店', '长沙美食：臭豆腐、口味虾；张家界美食：三下锅、土家腊肉', '1. 张家界风景优美，建议穿舒适的鞋子；2. 长沙到张家界高铁约2小时；3. 湖南菜偏辣，可根据口味调整', '2026-03-12 21:07:42', NULL);
INSERT INTO `travel_plan` VALUES ('TPe924159f42', 1, '北京', 6, 3000, 'culturalExploration', '我想去北京，然后再去上海玩', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'故宫\', \'天坛公园\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'八达岭长城\', \'居庸关\']}, {\'day\': 4, \'content\': \'第四天行程描述\', \'spots\': [\'国家博物馆\', \'南锣鼓巷\']}, {\'day\': 5, \'content\': \'第五天行程描述\', \'spots\': [\'景山公园\', \'王府井大街\']}, {\'day\': 6, \'content\': \'第六天行程描述\', \'spots\': [\'首都博物馆\', \'前门大街\']}]', '推荐住在市中心，方便游览景点，如北京金融街丽思卡尔顿酒店。', '尝试北京烤鸭、炸酱面、豆汁儿等特色美食。', '提前预订景点门票，避免排队；注意保暖，北京早晚温差较大。', '2026-03-12 20:26:39', NULL);
INSERT INTO `travel_plan` VALUES ('TPecdd5c76a0', 1, '北京/上海', 5, 3000, 'culturalExploration', '我想去北京，再去上海', '[{\'day\': 1, \'content\': \'第一天（北京）：抵达北京，游览故宫、天安门广场\', \'spots\': [\'故宫\', \'天安门广场\']}, {\'day\': 2, \'content\': \'第二天（北京）：参观长城、颐和园\', \'spots\': [\'八达岭长城\', \'颐和园\']}, {\'day\': 3, \'content\': \'第三天（北京）：游览圆明园、首都博物馆\', \'spots\': [\'圆明园\', \'首都博物馆\']}, {\'day\': 4, \'content\': \'第四天（上海）：从北京前往上海，游览外滩、南京路步行街\', \'spots\': [\'外滩\', \'南京路步行街\']}, {\'day\': 5, \'content\': \'第五天（上海）：参观豫园、上海博物馆\', \'spots\': [\'豫园\', \'上海博物馆\']}]', '北京推荐：北京丽枫酒店；上海推荐：上海浦东香格里拉大酒店', '北京美食：炸酱面、京味烤鸭；上海美食：小笼包、生煎包', '1. 北京到上海高铁约5小时；2. 上海景点集中，建议使用地铁或打车', '2026-03-12 21:09:10', NULL);
