INSERT INTO `travel_plan` VALUES ('TPf91630692f', 1, '北京', 3, 3000, 'culturalExploration', '我想去北京', '[{\'day\': 1, \'content\': \'第一天（北京）：抵达北京，游览故宫、天安门广场\', \'spots\': [\'故宫\', \'天安门广场\']}, {\'day\': 2, \'content\': \'第二天（北京）：参观颐和园、圆明园\', \'spots\': [\'颐和园\', \'圆明园\']}, {\'day\': 3, \'content\': \'第三天（北京）：游览八达岭长城、返回\', \'spots\': [\'八达岭长城\']}]', '北京推荐：北京京仪大酒店', '北京美食：烤鸭、炸酱面、豆汁焦圈', '1. 北京地铁覆盖广泛，建议购买交通卡；2. 八达岭长城较远，建议提前预订包车或大巴', '2026-03-19 19:55:03', '[\'文化探索丰富\', \'景点集中省时\', \'交通便捷高效\', \'体验历史氛围浓厚\']');
INSERT INTO `travel_plan` VALUES ('TPf9957fc371', 1, '上海', 3, 3000, 'culturalExploration', '我想去上海', '[{\'day\': 1, \'content\': \'第一天（上海）：抵达上海，游览外滩、南京路\', \'spots\': [\'外滩\', \'南京路\']}, {\'day\': 2, \'content\': \'第二天（上海）：参观上海博物馆、豫园\', \'spots\': [\'上海博物馆\', \'豫园\']}, {\'day\': 3, \'content\': \'第三天（上海）：游览田子坊、新天地\', \'spots\': [\'田子坊\', \'新天地\']}]', '上海推荐：上海浦东丽思卡尔顿酒店', '上海美食：小笼包、生煎、蟹粉豆腐', '1. 上海地铁方便，建议购买交通卡；2. 夏季注意防晒', '2026-03-17 20:24:59', NULL);
INSERT INTO `travel_plan` VALUES ('TPfd39440ec2', 1, '月球', 3, 3000, 'culturalExploration', '我想去月球', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'环形山\', \'月海\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'月球基地\', \'陨石坑\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'月球表面探索\', \'返回地球\']}]', '月球基地住宿，提供基本生活设施', '太空营养餐，包括脱水食品和新鲜水果', '请确保携带足够的氧气瓶和防护服，注意月球表面的温度变化', '2026-03-11 08:34:44', NULL);
INSERT INTO `travel_plan` VALUES ('TPfd91beaa8b', 1, '长沙', 6, 3000, 'culturalExploration', '我想去长沙，并且经过上海', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'上海博物馆\', \'外滩\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'岳麓山\', \'橘子洲头\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'湖南省博物馆\', \'天心阁\']}, {\'day\': 4, \'content\': \'第四天行程描述\', \'spots\': [\'岳麓书院\', \'橘子洲头\']}, {\'day\': 5, \'content\': \'第五天行程描述\', \'spots\': [\'文庙\', \'太平老街\']}, {\'day\': 6, \'content\': \'第六天行程描述\', \'spots\': [\'湖南烈士公园\', \'黄兴路步行街\']}]', '推荐住在市中心，方便出行，如五一广场附近酒店。', '必尝美食包括臭豆腐、口味虾、剁椒鱼头和糖油粑粑。', '注意天气变化，携带适合的衣物；尽量使用公共交通，节省费用。', '2026-03-12 20:22:50', NULL);
INSERT INTO `travel_plan` VALUES ('TPffa2fb0000', 1, '北京', 6, 3000, 'culturalExploration', '我想去北京，然后去长沙', '[{\'day\': 1, \'content\': \'第一天行程描述\', \'spots\': [\'故宫\', \'天坛公园\']}, {\'day\': 2, \'content\': \'第二天行程描述\', \'spots\': [\'长城\', \'颐和园\']}, {\'day\': 3, \'content\': \'第三天行程描述\', \'spots\': [\'圆明园\', \'国家博物馆\']}, {\'day\': 4, \'content\': \'第四天行程描述\', \'spots\': [\'南锣鼓巷\', \'五道营胡同\']}, {\'day\': 5, \'content\': \'第五天行程描述\', \'spots\': [\'景山公园\', \'首都博物馆\']}, {\'day\': 6, \'content\': \'第六天行程描述\', \'spots\': [\'奥林匹克公园\', \'鸟巢\']}]', '推荐住在市中心，方便游览景点的经济型酒店。', '尝试北京烤鸭、炸酱面、豆汁焦圈等特色美食。', '提前预订景点门票，避免排队；注意保暖，北京早晚温差大。', '2026-03-12 20:36:56', NULL);
