DROP TABLE IF EXISTS `hotel`;
CREATE TABLE `hotel`  (
  `hotelId` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '酒店唯一ID',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '酒店名称',
  `name_en` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '酒店名称（英文）',
  `image` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '酒店主图URL',
  `images` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '酒店图片列表（逗号分隔）',
  `rating` decimal(2, 1) NULL DEFAULT NULL COMMENT '评分',
  `reviewCount` int NULL DEFAULT NULL COMMENT '评论数',
  `address` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '酒店地址',
  `address_en` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '地址（英文）',
  `price` decimal(10, 2) NOT NULL COMMENT '酒店单价（元/晚）',
  `originalPrice` decimal(10, 2) NULL DEFAULT NULL COMMENT '原价',
  `star` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '酒店星级（三星/四星/五星）',
  `type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '酒店类型',
  `type_en` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '酒店类型（英文）',
  `distance` decimal(5, 1) NULL DEFAULT NULL COMMENT '距离（单位km）',
  `facility` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '酒店设施（逗号分隔）',
  `facility_en` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '设施（英文，逗号分隔）',
  `tags` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '标签（中文，逗号分隔）',
  `tags_en` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '标签（英文，逗号分隔）',
  `roomType` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '房型（逗号分隔）',
  `latitude` decimal(9, 6) NULL DEFAULT NULL COMMENT '纬度',
  `longitude` decimal(9, 6) NULL DEFAULT NULL COMMENT '经度',
  `description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '酒店描述',
  `commentScore` decimal(2, 1) NULL DEFAULT NULL COMMENT '点评分数（1.0-5.0）',
  PRIMARY KEY (`hotelId`) USING BTREE,
  INDEX `idx_hotel_address`(`address` ASC) USING BTREE,
  INDEX `idx_hotel_star`(`star` ASC) USING BTREE,
  INDEX `idx_hotel_price`(`price` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '九州Traveling酒店表' ROW_FORMAT = Dynamic;

