DROP TABLE IF EXISTS `mobile_house`;
CREATE TABLE `mobile_house`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '小窝ID',
  `title` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '小窝名称',
  `intro` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '小窝简介',
  `cover_image` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '封面图片URL',
  `address` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '详细地址',
  `location_lng` decimal(10, 6) NULL DEFAULT NULL COMMENT '经度',
  `location_lat` decimal(10, 6) NULL DEFAULT NULL COMMENT '纬度',
  `contact` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '联系方式（电话/微信）',
  `price` decimal(10, 2) NOT NULL COMMENT '价格/晚',
  `checkin_time` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '入住时间（如 14:00后）',
  `checkout_time` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '退房时间（如 12:00前）',
  `tags` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '标签（逗号分隔，如 民宿,近地铁,可做饭）',
  `rating` decimal(3, 2) NULL DEFAULT 5.00 COMMENT '评分',
  `review_count` int NULL DEFAULT 0 COMMENT '评论数',
  `distance` decimal(5, 2) NULL DEFAULT NULL COMMENT '距离当前位置（km，前端计算）',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 15 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '旅行小窝表' ROW_FORMAT = Dynamic;

