DROP TABLE IF EXISTS `travel_plan`;
CREATE TABLE `travel_plan`  (
  `planId` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '行程唯一ID',
  `user_id` int NOT NULL COMMENT '所属用户ID（关联users表id）',
  `destination` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '旅行目的地',
